INSERT INTO `documentation_items` VALUES (3,'Configure Discovery Settings','configure-discovery-settings','<p class=\"MsoListParagraphCxSpFirst\" style=\"\r\n    margin: 12pt 0cm 12pt 36pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \"><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\"><span style=\"font: 7pt \'Times New Roman\'\"><span>&nbsp;</span></span></span><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">Under the<span>&nbsp;</span><b>Device Discovery</b><span>&nbsp;</span>section:</span>\r\n</p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n    margin: 12pt 0cm 12pt 72pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \">\r\n  <span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">a.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">Enable Device Discovery</span></b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">: Check to enable automatic discovery</span>\r\n</p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n    margin: 12pt 0cm 12pt 72pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \">\r\n  <span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">b.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">Discovery Threads</span></b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">: Set number of concurrent discovery processes (typically 1-5)</span>\r\n</p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n    margin: 12pt 0cm 12pt 72pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \">\r\n  <span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">c.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">Ping Method</span></b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">: Choose ICMP, TCP, or UDP</span>\r\n</p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n    margin: 12pt 0cm 12pt 72pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \">\r\n  <span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">d.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">SNMP Version</span></b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">: Select v1, v2c, or v3</span>\r\n</p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n    margin: 12pt 0cm 12pt 72pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \">\r\n  <span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">e.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">SNMP Community</span></b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">: Set default community string if using v1/v2c</span>\r\n</p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n    margin: 12pt 0cm 12pt 72pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \">\r\n  <span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">f.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">SNMP Timeout</span></b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">: Set timeout in milliseconds (default 500)</span>\r\n</p>\r\n<p class=\"MsoListParagraphCxSpLast\" style=\"\r\n    margin: 12pt 0cm 12pt 72pt;\r\n    line-height: 28.48px;\r\n    font-size: medium;\r\n    font-family: Aptos, sans-serif;\r\n    color: rgb(0, 0, 0);\r\n    font-style: normal;\r\n    font-variant-ligatures: normal;\r\n    font-variant-caps: normal;\r\n    font-weight: 400;\r\n    letter-spacing: normal;\r\n    orphans: 2;\r\n    text-align: start;\r\n    text-transform: none;\r\n    widows: 2;\r\n    word-spacing: 0px;\r\n    -webkit-text-stroke-width: 0px;\r\n    white-space: normal;\r\n    text-decoration-thickness: initial;\r\n    text-decoration-style: initial;\r\n    text-decoration-color: initial;\r\n    text-indent: -18pt;\r\n  \">\r\n  <span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">g.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">SNMP Retries</span></b><span lang=\"EN-US\" style=\"font-family: \'system-ui\', serif; color: rgb(64, 64, 64)\">: Set number of retry attempts (default 3)</span>\r\n</p>\r\n',0,0,'active','2025-08-19 10:20:41','2025-08-28 11:43:13'),(4,'Schedule Automatic Discovery','schedule-automatic-discovery','<div class=\"steps\"><ol>\r\n              <li>Go to <code>Console → Configuration → Automation</code>.</li>\r\n              <li>Select <code>Network Discovery</code>.</li>\r\n              <li>\r\n                Click <strong>Add</strong> and define an IP range (e.g.,\r\n                <code>192.168.1.0/24</code>).\r\n              </li>\r\n              <li>\r\n                Set frequency (<em>Daily</em>, <em>Weekly</em>,\r\n                <em>Monthly</em>) and time.\r\n              </li>\r\n            </ol>\r\n          </div>',0,NULL,'active','2025-08-19 10:21:12','2025-08-26 09:02:18'),(5,'Configure Discovery Poller','configure-discovery-poller','<div class=\"param\">\r\n  <p class=\"MsoListParagraphCxSpFirst\" style=\"\r\n      margin: 12pt 0cm 12pt 36pt;\r\n      line-height: 28.48px;\r\n      font-size: medium;\r\n      font-family: Aptos, sans-serif;\r\n      color: rgb(0, 0, 0);\r\n      font-style: normal;\r\n      font-variant-ligatures: normal;\r\n      font-variant-caps: normal;\r\n      font-weight: 400;\r\n      letter-spacing: normal;\r\n      orphans: 2;\r\n      text-align: start;\r\n      text-transform: none;\r\n      widows: 2;\r\n      word-spacing: 0px;\r\n      -webkit-text-stroke-width: 0px;\r\n      white-space: normal;\r\n      text-decoration-thickness: initial;\r\n      text-decoration-style: initial;\r\n      text-decoration-color: initial;\r\n      text-indent: -18pt;\r\n    \">\r\n    <b><span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">1.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span></b><span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">Navigate back to:<span>&nbsp;</span><b>Console &gt; Configuration &gt; Settings &gt; Poller</b></span>\r\n  </p>\r\n  <p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n      margin: 12pt 0cm 12pt 36pt;\r\n      line-height: 28.48px;\r\n      font-size: medium;\r\n      font-family: Aptos, sans-serif;\r\n      color: rgb(0, 0, 0);\r\n      font-style: normal;\r\n      font-variant-ligatures: normal;\r\n      font-variant-caps: normal;\r\n      font-weight: 400;\r\n      letter-spacing: normal;\r\n      orphans: 2;\r\n      text-align: start;\r\n      text-transform: none;\r\n      widows: 2;\r\n      word-spacing: 0px;\r\n      -webkit-text-stroke-width: 0px;\r\n      white-space: normal;\r\n      text-decoration-thickness: initial;\r\n      text-decoration-style: initial;\r\n      text-decoration-color: initial;\r\n      text-indent: -18pt;\r\n    \">\r\n    <span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">2.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">Under<span>&nbsp;</span><b>Device Discovery</b>:</span>\r\n  </p>\r\n  <p class=\"MsoListParagraphCxSpMiddle\" style=\"\r\n      margin: 12pt 0cm 12pt 72pt;\r\n      line-height: 28.48px;\r\n      font-size: medium;\r\n      font-family: Aptos, sans-serif;\r\n      color: rgb(0, 0, 0);\r\n      font-style: normal;\r\n      font-variant-ligatures: normal;\r\n      font-variant-caps: normal;\r\n      font-weight: 400;\r\n      letter-spacing: normal;\r\n      orphans: 2;\r\n      text-align: start;\r\n      text-transform: none;\r\n      widows: 2;\r\n      word-spacing: 0px;\r\n      -webkit-text-stroke-width: 0px;\r\n      white-space: normal;\r\n      text-decoration-thickness: initial;\r\n      text-decoration-style: initial;\r\n      text-decoration-color: initial;\r\n      text-indent: -18pt;\r\n    \">\r\n    <span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">a.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">Discovery Interval</span></b><span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">: How often to run discovery (in minutes)</span>\r\n  </p>\r\n  <p class=\"MsoListParagraphCxSpLast\" style=\"\r\n      margin: 12pt 0cm 12pt 72pt;\r\n      line-height: 28.48px;\r\n      font-size: medium;\r\n      font-family: Aptos, sans-serif;\r\n      color: rgb(0, 0, 0);\r\n      font-style: normal;\r\n      font-variant-ligatures: normal;\r\n      font-variant-caps: normal;\r\n      font-weight: 400;\r\n      letter-spacing: normal;\r\n      orphans: 2;\r\n      text-align: start;\r\n      text-transform: none;\r\n      widows: 2;\r\n      word-spacing: 0px;\r\n      -webkit-text-stroke-width: 0px;\r\n      white-space: normal;\r\n      text-decoration-thickness: initial;\r\n      text-decoration-style: initial;\r\n      text-decoration-color: initial;\r\n      text-indent: -18pt;\r\n    \">\r\n    <span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">b.<span style=\"font: 7pt \'Times New Roman\'\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;</span></span></span><b><span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">Max Runtime</span></b><span lang=\"EN-US\" style=\"font-family: Inter, serif; color: rgb(64, 64, 64)\">: Maximum time for discovery to run (in seconds)</span>\r\n  </p>\r\n</div>\r\n',0,0,'active','2025-08-19 10:21:35','2025-08-28 11:41:37'),(6,'Manual Discovery','manual-discovery','<div class=\"steps\"><ol>\r\n              <li>Go to <code>Console → Utilities → Automation</code>.</li>\r\n              <li>Select <code>Network Discovery</code>.</li>\r\n              <li>Click <strong>Execute</strong> to run immediately.</li>\r\n            </ol>\r\n          </div>',0,NULL,'active','2025-08-19 10:23:10','2025-08-26 09:02:27'),(7,'Verify Discovery Setting','verify-discovery-setting','<div class=\"param\">\r\n            <h3>Logs</h3>\r\n            <ol>\r\n              <li>\r\n                Go to\r\n                <code>Console → System Utilities → View InfiworxNMS Log</code>.\r\n              </li>\r\n              <li>Filter for <code>AUTOMATION</code> entries.</li>\r\n            </ol>\r\n            <h3>Discovered Devices</h3>\r\n            <ol>\r\n              <li>\r\n                Go to <code>Console → Management → Devices</code> to see\r\n                results.\r\n              </li>\r\n            </ol>\r\n          </div>',0,0,'active','2025-08-19 10:23:32','2025-08-20 11:59:25'),(8,'Access Threshold Management','access-threshold-management','<div class=\"steps\"><ol>\r\n              <li>Go to <code>Console → Configuration → Automation</code>.</li>\r\n              <li>Select <code>Network Discovery</code>.</li>\r\n              <li>\r\n                Click <strong>Add</strong> and define an IP range (e.g.,\r\n                <code>192.168.1.0/24</code>).\r\n              </li>\r\n              <li>\r\n                Set frequency (<em>Daily</em>, <em>Weekly</em>,\r\n                <em>Monthly</em>) and time.\r\n              </li>\r\n            </ol>\r\n          </div>',0,NULL,'active','2025-08-19 10:23:58','2025-08-26 09:02:47'),(9,'Create New Threshold','create-new-threshold','<div class=\"param\">\n            <h3>Basic Settings</h3>\n            <ul>\n              <li><strong>Name</strong> — descriptive label.</li>\n              <li><strong>Data Source</strong> — graph/data source.</li>\n              <li>\n                <strong>Threshold Type</strong> — High/Low, Baseline deviation,\n                or Time-based.\n              </li>\n            </ul>\n          </div>',0,NULL,'active','2025-08-19 10:24:19','2025-08-20 11:59:22'),(10,'Configure Threshold Parameters','configure-threshold-parameters','<div class=\"param\">\n            <h3>Value Settings</h3>\n            <ul>\n              <li><strong>High Threshold</strong> — upper limit.</li>\n              <li><strong>Low Threshold</strong> — lower limit.</li>\n              <li>\n                <strong>Percentage</strong> — percentage-based thresholds.\n              </li>\n              <li><strong>Time Range</strong> — for time-based thresholds.</li>\n            </ul>\n            <h3>Alert Settings</h3>\n            <ul>\n              <li>\n                <strong>Trigger Condition</strong> — consecutive breaches before\n                alert.\n              </li>\n              <li><strong>Alert Email</strong> — notification recipients.</li>\n              <li><strong>Alert Message</strong> — custom message.</li>\n            </ul>\n            <h3>Advanced Options</h3>\n            <ul>\n              <li><strong>RPN Expression</strong> — advanced calculations.</li>\n              <li>\n                <strong>Re-Alert Cycle</strong> — resend interval (minutes).\n              </li>\n            </ul>\n          </div>',0,NULL,'active','2025-08-19 10:24:43','2025-08-20 10:13:30'),(11,'Threshold Templates','threshold-templates','<div class=\"steps\"><ol>\r\n              <li>\r\n                Go to <code>Console → Templates → Threshold Templates</code>.\r\n              </li>\r\n              <li>\r\n                Click <strong>Add</strong> and configure reusable template.\r\n              </li>\r\n              <li>Apply template to multiple data sources.</li>\r\n            </ol>\r\n          </div>',0,NULL,'active','2025-08-19 10:25:09','2025-08-26 09:03:23'),(12,'Enable Threshold Checking','enable-threshold-checking','<div class=\"param\">\n            <h3>Poller Settings</h3>\n            <ul>\n              <li><strong>Enable Threshold Checking</strong> — toggle ON.</li>\n              <li>\n                <strong>Check Interval</strong> — default\n                <code>5 minutes</code>.\n              </li>\n              <li><strong>Max Runtime</strong> — evaluation cap (seconds).</li>\n            </ul>\n          </div>',0,NULL,'active','2025-08-19 10:25:37','2025-08-26 05:55:34'),(15,'Add New Network Discovery Range','add-new-network-discovery-range','<h3 data-start=\"245\" data-end=\"259\">Main Fields</h3><ul data-start=\"261\" data-end=\"761\">\r\n<li data-start=\"261\" data-end=\"324\">\r\n<p data-start=\"263\" data-end=\"324\"><strong data-start=\"263\" data-end=\"272\">Name:</strong> Enter a descriptive name for the discovery range.</p>\r\n</li>\r\n<li data-start=\"325\" data-end=\"408\">\r\n<p data-start=\"327\" data-end=\"408\"><strong data-start=\"327\" data-end=\"353\">Alternate DNS Servers:</strong> Optional. Specify DNS IPs/FQDNs for name resolution.</p>\r\n</li>\r\n<li data-start=\"409\" data-end=\"477\">\r\n<p data-start=\"411\" data-end=\"477\"><strong data-start=\"411\" data-end=\"428\">Subnet Range:</strong> Enter in CIDR format (e.g., <code data-start=\"457\" data-end=\"473\">192.168.1.0/24</code>).</p>\r\n</li>\r\n<li data-start=\"478\" data-end=\"541\">\r\n<p data-start=\"480\" data-end=\"541\"><strong data-start=\"480\" data-end=\"499\">Data Collector:</strong> Select which poller will run discovery.</p>\r\n</li>\r\n<li data-start=\"542\" data-end=\"604\">\r\n<p data-start=\"544\" data-end=\"604\"><strong data-start=\"544\" data-end=\"564\">Associated Site:</strong> Assign the subnet to a site/location.</p>\r\n</li>\r\n<li data-start=\"605\" data-end=\"696\">\r\n<p data-start=\"607\" data-end=\"696\"><strong data-start=\"607\" data-end=\"629\">Discovery Threads:</strong> Number of concurrent scans (more threads = faster, higher load).</p>\r\n</li>\r\n<li data-start=\"697\" data-end=\"761\">\r\n<p data-start=\"699\" data-end=\"761\"><strong data-start=\"699\" data-end=\"713\">Run Limit:</strong> Max time allowed for the scan (e.g., 20 min).</p>\r\n</li></ul><h3 data-start=\"768\" data-end=\"788\">Options (Toggles)</h3><ul data-start=\"790\" data-end=\"1104\">\r\n<li data-start=\"790\" data-end=\"837\">\r\n<p data-start=\"792\" data-end=\"837\"><strong data-start=\"792\" data-end=\"804\">Enabled:</strong> Turns subnet discovery on/off.</p>\r\n</li>\r\n<li data-start=\"838\" data-end=\"886\">\r\n<p data-start=\"840\" data-end=\"886\"><strong data-start=\"840\" data-end=\"852\">NetBIOS:</strong> Enables NetBIOS name discovery.</p>\r\n</li>\r\n<li data-start=\"887\" data-end=\"957\">\r\n<p data-start=\"889\" data-end=\"957\"><strong data-start=\"889\" data-end=\"918\">Auto Add to Infoworx/NMS:</strong> Automatically imports found devices.</p>\r\n</li>\r\n<li data-start=\"958\" data-end=\"1029\">\r\n<p data-start=\"960\" data-end=\"1029\"><strong data-start=\"960\" data-end=\"983\">Allow same sysName:</strong> Allows duplicate system names across hosts.</p>\r\n</li>\r\n<li data-start=\"1030\" data-end=\"1104\">\r\n<p data-start=\"1032\" data-end=\"1104\"><strong data-start=\"1032\" data-end=\"1055\">Rerun Data Queries:</strong> Refreshes info for already discovered devices.</p>\r\n</li></ul><h3 data-start=\"1111\" data-end=\"1118\">Tips</h3><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><ul data-start=\"1119\" data-end=\"1294\">\r\n<li data-start=\"1119\" data-end=\"1168\">\r\n<p data-start=\"1121\" data-end=\"1168\">Use meaningful names for easy identification.</p>\r\n</li>\r\n<li data-start=\"1169\" data-end=\"1224\">\r\n<p data-start=\"1171\" data-end=\"1224\">Match <strong data-start=\"1177\" data-end=\"1190\">Run Limit</strong> and <strong data-start=\"1195\" data-end=\"1206\">Threads</strong> to subnet size.</p>\r\n</li>\r\n<li data-start=\"1225\" data-end=\"1294\">\r\n<p data-start=\"1227\" data-end=\"1294\">Add <strong data-start=\"1231\" data-end=\"1248\">Alternate DNS</strong> if default servers don’t resolve hostnames.</p></li></ul>',0,NULL,'active','2025-08-25 04:49:24','2025-08-29 11:47:23'),(16,'Host Device','host-device','<h3 data-start=\"133\" data-end=\"166\"><span data-start=\"137\" data-end=\"166\" style=\"font-weight: normal;\">1. General Device Options</span></h3>\r\n<ul data-start=\"167\" data-end=\"437\"><li data-start=\"167\" data-end=\"233\">\r\n<p data-start=\"169\" data-end=\"233\"><strong data-start=\"169\" data-end=\"195\">Description / Hostname</strong>: Provide device name and IP/hostname.</p>\r\n</li><li data-start=\"234\" data-end=\"309\">\r\n<p data-start=\"236\" data-end=\"309\"><strong data-start=\"236\" data-end=\"275\">Location / Poller / Site / Template</strong>: Select appropriate associations.</p>\r\n</li><li data-start=\"310\" data-end=\"382\">\r\n<p data-start=\"312\" data-end=\"382\"><strong data-start=\"312\" data-end=\"334\">Collection Threads</strong>: Set the number of threads (default if unsure).</p>\r\n</li><li data-start=\"383\" data-end=\"437\">\r\n<p data-start=\"385\" data-end=\"437\"><strong data-start=\"385\" data-end=\"403\">Disable Device</strong>: Toggle to disable/enable device</p></li></ul>\r\n<h3 data-start=\"444\" data-end=\"467\"><span data-start=\"448\" data-end=\"467\" style=\"font-weight: normal;\">2. Map Settings</span></h3>\r\n<ul data-start=\"468\" data-end=\"532\"><li data-start=\"468\" data-end=\"532\">\r\n<p data-start=\"470\" data-end=\"532\"><strong data-start=\"470\" data-end=\"494\">Latitude / Longitude</strong>: Enter coordinates for map placement.</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"539\" data-end=\"562\"><span data-start=\"543\" data-end=\"562\" style=\"font-weight: normal;\">3. SNMP Options</span></h3>\r\n<ul data-start=\"563\" data-end=\"631\"><li data-start=\"563\" data-end=\"631\">\r\n<p data-start=\"565\" data-end=\"631\"><strong data-start=\"565\" data-end=\"581\">SNMP Version</strong>: Choose version (e.g., Not In Use, SNMPv1/v2/v3).</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"638\" data-end=\"675\"><span data-start=\"642\" data-end=\"675\" style=\"font-weight: normal;\">4. Device Monitoring Settings</span></h3>\r\n<ul data-start=\"676\" data-end=\"1016\"><li data-start=\"676\" data-end=\"723\">\r\n<p data-start=\"678\" data-end=\"723\"><strong data-start=\"678\" data-end=\"696\">Monitor Device</strong>: Toggle monitoring on/off.</p>\r\n</li><li data-start=\"724\" data-end=\"794\">\r\n<p data-start=\"726\" data-end=\"794\"><strong data-start=\"726\" data-end=\"748\">Device Criticality</strong>: Set importance level (Disabled to Critical).</p>\r\n</li><li data-start=\"795\" data-end=\"840\">\r\n<p data-start=\"797\" data-end=\"840\"><strong data-start=\"797\" data-end=\"812\">Device Icon</strong>: Select icon (e.g., SDWAN).</p>\r\n</li><li data-start=\"841\" data-end=\"903\">\r\n<p data-start=\"843\" data-end=\"903\"><strong data-start=\"843\" data-end=\"876\">Ping Warning/Alert Thresholds</strong>: Enter latency thresholds.</p>\r\n</li><li data-start=\"904\" data-end=\"964\">\r\n<p data-start=\"906\" data-end=\"964\"><strong data-start=\"906\" data-end=\"929\">Re-Baseline Options</strong>: Choose to update alert baselines.</p>\r\n</li><li data-start=\"965\" data-end=\"1016\">\r\n<p data-start=\"967\" data-end=\"1016\"><strong data-start=\"967\" data-end=\"990\">Down Device Message</strong>: Optional custom message.</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"1023\" data-end=\"1069\"><span data-start=\"1027\" data-end=\"1069\" style=\"font-weight: normal;\">5. Availability / Reachability Options</span></h3>\r\n<ul data-start=\"1070\" data-end=\"1205\"><li data-start=\"1070\" data-end=\"1135\">\r\n<p data-start=\"1072\" data-end=\"1135\"><strong data-start=\"1072\" data-end=\"1099\">Downed Device Detection</strong>: Choose method (e.g., SNMP Uptime).</p>\r\n</li><li data-start=\"1136\" data-end=\"1205\">\r\n<p data-start=\"1138\" data-end=\"1205\"><strong data-start=\"1138\" data-end=\"1168\">Ping Timeout / Retry Count</strong>: Set values (e.g., 400 ms, 1 retry).</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"1212\" data-end=\"1241\"><span data-start=\"1216\" data-end=\"1241\" style=\"font-weight: normal;\">6. Additional Options</span></h3>\r\n<ul data-start=\"1242\" data-end=\"1338\"><li data-start=\"1242\" data-end=\"1294\">\r\n<p data-start=\"1244\" data-end=\"1294\"><strong data-start=\"1244\" data-end=\"1253\">Notes</strong>: Add comments or internal documentation.</p>\r\n</li><li data-start=\"1295\" data-end=\"1338\">\r\n<p data-start=\"1297\" data-end=\"1338\"><strong data-start=\"1297\" data-end=\"1312\">External ID</strong>: For system integrations.</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"1345\" data-end=\"1367\"><span data-start=\"1349\" data-end=\"1367\" style=\"font-weight: normal;\">7. Final Steps</span></h3>\r\n<ul data-start=\"1368\" data-end=\"1437\"><li data-start=\"1368\" data-end=\"1396\">\r\n<p data-start=\"1370\" data-end=\"1396\"><strong data-start=\"1370\" data-end=\"1380\">Update</strong>: Save settings.</p>\r\n</li><li data-start=\"1397\" data-end=\"1437\">\r\n<p data-start=\"1399\" data-end=\"1437\"><strong data-start=\"1399\" data-end=\"1411\">Previous</strong>: Go back to prior screen.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-25 04:52:31','2025-08-28 11:33:09'),(18,'Device Metrices','device-metrices','<p>This dashboard provides an overview of the device metrics for your network infrastructure. It includes information about device status, alarm summary, incidents, latency, and availability of hosts.</p><h3 data-start=\"5227\" data-end=\"5244\">Key Features:</h3>\r\n<ul data-start=\"5245\" data-end=\"5832\"><li data-start=\"5245\" data-end=\"5342\">\r\n<p data-start=\"5247\" data-end=\"5342\"><strong data-start=\"5247\" data-end=\"5278\">Device Category Wise Status</strong>: Shows up/down status for switches, routers, and other devices.</p>\r\n</li><li data-start=\"5343\" data-end=\"5432\">\r\n<p data-start=\"5345\" data-end=\"5432\"><strong data-start=\"5345\" data-end=\"5362\">Alarm Summary</strong>: Displays the number of devices in normal, warning, and alert states.</p>\r\n</li><li data-start=\"5433\" data-end=\"5498\">\r\n<p data-start=\"5435\" data-end=\"5498\"><strong data-start=\"5435\" data-end=\"5452\">Device Status</strong>: Shows the operational status of all devices.</p>\r\n</li><li data-start=\"5499\" data-end=\"5590\">\r\n<p data-start=\"5501\" data-end=\"5590\"><strong data-start=\"5501\" data-end=\"5514\">Incidents</strong>: Provides insights into incidents over the last 10 days and their statuses.</p>\r\n</li><li data-start=\"5591\" data-end=\"5677\">\r\n<p data-start=\"5593\" data-end=\"5677\"><strong data-start=\"5593\" data-end=\"5604\">Latency</strong>: Displays the network latency for devices, with a color-coded indicator.</p>\r\n</li><li data-start=\"5678\" data-end=\"5748\">\r\n<p data-start=\"5680\" data-end=\"5748\"><strong data-start=\"5680\" data-end=\"5702\">Load Average Trend</strong>: Shows how device load has changed over time.</p>\r\n</li><li data-start=\"5749\" data-end=\"5832\">\r\n<p data-start=\"5751\" data-end=\"5832\"><strong data-start=\"5751\" data-end=\"5772\">Host Availability</strong>: A table showing uptime and availability for various hosts.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-28 07:08:00','2025-08-28 07:08:00'),(19,'GIS MAP','gis-map','<p>The GIS Map section provides a visual representation of the network devices mapped to geographical locations. It allows you to monitor the status of devices based on their physical locations.</p><h3 data-start=\"3776\" data-end=\"3804\">Key Features of GIS Map:</h3>\r\n<ol data-start=\"3805\" data-end=\"4239\"><li data-start=\"3805\" data-end=\"3968\">\r\n<p data-start=\"3808\" data-end=\"3968\"><strong data-start=\"3808\" data-end=\"3828\">Device Locations</strong>: The map displays devices\' geographical locations with colored markers to represent their status (green for \"Up\" and yellow for \"Unknown\").</p>\r\n</li><li data-start=\"3969\" data-end=\"4101\">\r\n<p data-start=\"3972\" data-end=\"4101\"><strong data-start=\"3972\" data-end=\"4000\">Device Status Indicators</strong>: Green markers show operational devices, while yellow markers represent devices with unknown status.</p>\r\n</li><li data-start=\"4102\" data-end=\"4239\">\r\n<p data-start=\"4105\" data-end=\"4239\"><strong data-start=\"4105\" data-end=\"4121\">Map Controls</strong>: Zooming, device information pop-ups, and map type toggles are available for better navigation and detailed insights.</p></li></ol><p><br></p>',0,NULL,'active','2025-08-28 07:10:44','2025-08-28 07:10:44'),(20,'Reports','reports','<p>The Reports section provides tools to generate and filter reports for various network services and devices. You can filter the data by hostname, service name, and time duration to get the desired insights</p><h3 data-start=\"5020\" data-end=\"5060\">Key Features of the Reports Section:</h3>\r\n<ol data-start=\"5061\" data-end=\"5470\"><li data-start=\"5061\" data-end=\"5177\">\r\n<p data-start=\"5064\" data-end=\"5177\"><strong data-start=\"5064\" data-end=\"5075\">Filters</strong>: The ability to filter reports based on hostname, service name, duration, and the prediction feature.</p>\r\n</li><li data-start=\"5178\" data-end=\"5315\">\r\n<p data-start=\"5181\" data-end=\"5315\"><strong data-start=\"5181\" data-end=\"5202\">Report Generation</strong>: Once filters are selected, the system generates the corresponding reports, which are shown in a tabular format.</p>\r\n</li><li data-start=\"5316\" data-end=\"5470\">\r\n<p data-start=\"5319\" data-end=\"5470\"><strong data-start=\"5319\" data-end=\"5335\">Report Table</strong>: Displays the generated report with the chosen filters, including columns for hostname, service name, duration, and prediction status.</p></li></ol><p><br></p>',0,NULL,'active','2025-08-28 07:14:04','2025-08-28 07:14:04'),(21,'Network Discovery Range','network-discovery-range','<h4 data-start=\"249\" data-end=\"277\"><span style=\"font-weight: normal;\">1. <span data-start=\"257\" data-end=\"277\">General Settings</span></span></h4>\r\n<ul data-start=\"278\" data-end=\"719\"><li data-start=\"278\" data-end=\"327\">\r\n<p data-start=\"280\" data-end=\"327\"><strong data-start=\"280\" data-end=\"288\">Name</strong>: Assign a name (e.g., <code data-start=\"311\" data-end=\"325\">InfinityLabs</code>).</p>\r\n</li><li data-start=\"328\" data-end=\"392\">\r\n<p data-start=\"330\" data-end=\"392\"><strong data-start=\"330\" data-end=\"355\">Alternate DNS Servers</strong>: Enter IPs/FQDNs for DNS resolution.</p>\r\n</li><li data-start=\"393\" data-end=\"473\">\r\n<p data-start=\"395\" data-end=\"473\"><strong data-start=\"395\" data-end=\"411\">Subnet Range</strong>: Define the IP ranges for discovery (e.g., <code data-start=\"455\" data-end=\"471\">192.168.1.0/24</code>).</p>\r\n</li><li data-start=\"474\" data-end=\"539\">\r\n<p data-start=\"476\" data-end=\"539\"><strong data-start=\"476\" data-end=\"494\">Data Collector</strong>: Choose the collector (e.g., <code data-start=\"524\" data-end=\"537\">Main Poller</code>).</p>\r\n</li><li data-start=\"540\" data-end=\"594\">\r\n<p data-start=\"542\" data-end=\"594\"><strong data-start=\"542\" data-end=\"561\">Associated Site</strong>: Select the site (e.g., <code data-start=\"586\" data-end=\"592\">Core</code>).</p>\r\n</li><li data-start=\"595\" data-end=\"659\">\r\n<p data-start=\"597\" data-end=\"659\"><strong data-start=\"597\" data-end=\"618\">Discovery Threads</strong>: Set the number of threads (e.g., <code data-start=\"653\" data-end=\"657\">10</code>).</p>\r\n</li><li data-start=\"660\" data-end=\"719\">\r\n<p data-start=\"662\" data-end=\"719\"><strong data-start=\"662\" data-end=\"675\">Run Limit</strong>: Set maximum duration (e.g., <code data-start=\"705\" data-end=\"717\">20 minutes</code>).</p>\r\n</li></ul>\r\n<p data-start=\"721\" data-end=\"733\"><strong data-start=\"721\" data-end=\"732\">Options</strong>:</p>\r\n<ul data-start=\"734\" data-end=\"1036\"><li data-start=\"734\" data-end=\"776\">\r\n<p data-start=\"736\" data-end=\"776\"><strong data-start=\"736\" data-end=\"747\">Enabled</strong>: Toggle to enable discovery.</p>\r\n</li><li data-start=\"777\" data-end=\"821\">\r\n<p data-start=\"779\" data-end=\"821\"><strong data-start=\"779\" data-end=\"790\">NetBIOS</strong>: Enable/disable NetBIOS usage.</p>\r\n</li><li data-start=\"822\" data-end=\"900\">\r\n<p data-start=\"824\" data-end=\"900\"><strong data-start=\"824\" data-end=\"861\">Automatically Add to InfoWorx/NMS</strong>: Add discovered devices automatically.</p>\r\n</li><li data-start=\"901\" data-end=\"985\">\r\n<p data-start=\"903\" data-end=\"985\"><strong data-start=\"903\" data-end=\"944\">Allow Same SysName on Different Hosts</strong>: Allow same names for different devices.</p>\r\n</li><li data-start=\"986\" data-end=\"1036\">\r\n<p data-start=\"988\" data-end=\"1036\"><strong data-start=\"988\" data-end=\"1010\">Rerun Data Queries</strong>: Toggle to rerun queries.</p>\r\n</li></ul>\r\n\r\n<h4 data-start=\"1043\" data-end=\"1072\"><span style=\"font-weight: normal;\">2. <span data-start=\"1051\" data-end=\"1072\">Schedule Settings</span></span></h4>\r\n<ul data-start=\"1073\" data-end=\"1282\"><li data-start=\"1073\" data-end=\"1158\">\r\n<p data-start=\"1075\" data-end=\"1106\"><strong data-start=\"1075\" data-end=\"1092\">Schedule Type</strong>: Choose from:</p>\r\n<ul data-start=\"1109\" data-end=\"1158\"><li data-start=\"1109\" data-end=\"1158\">\r\n<p data-start=\"1111\" data-end=\"1158\"><strong data-start=\"1111\" data-end=\"1121\">Manual</strong>, <strong data-start=\"1123\" data-end=\"1132\">Daily</strong>, <strong data-start=\"1134\" data-end=\"1144\">Weekly</strong>, <strong data-start=\"1146\" data-end=\"1157\">Monthly</strong>.</p>\r\n</li></ul>\r\n</li><li data-start=\"1159\" data-end=\"1231\">\r\n<p data-start=\"1161\" data-end=\"1231\"><strong data-start=\"1161\" data-end=\"1183\">Starting Date/Time</strong>: Set the start time (e.g., <code data-start=\"1211\" data-end=\"1229\">2025-05-14 14:30</code>).</p>\r\n</li><li data-start=\"1232\" data-end=\"1282\">\r\n<p data-start=\"1234\" data-end=\"1282\"><strong data-start=\"1234\" data-end=\"1249\">Rerun Every</strong>: Set frequency (e.g., <code data-start=\"1272\" data-end=\"1280\">2 days</code>).</p>\r\n</li></ul>\r\n\r\n<h4 data-start=\"1289\" data-end=\"1322\"><span style=\"font-weight: normal;\">3. <span data-start=\"1297\" data-end=\"1322\">Reachability Settings</span></span></h4>\r\n<ul data-start=\"1323\" data-end=\"1609\"><li data-start=\"1323\" data-end=\"1396\">\r\n<p data-start=\"1325\" data-end=\"1396\"><strong data-start=\"1325\" data-end=\"1341\">SNMP Options</strong>: Choose SNMP settings (default: <code data-start=\"1374\" data-end=\"1394\">Default Option Set</code>).</p>\r\n</li><li data-start=\"1397\" data-end=\"1452\">\r\n<p data-start=\"1399\" data-end=\"1452\"><strong data-start=\"1399\" data-end=\"1414\">Ping Method</strong>: Select method (e.g., <strong data-start=\"1437\" data-end=\"1450\">ICMP Ping</strong>).</p>\r\n</li><li data-start=\"1453\" data-end=\"1497\">\r\n<p data-start=\"1455\" data-end=\"1497\"><strong data-start=\"1455\" data-end=\"1468\">Ping Port</strong>: Set ping port (e.g., <code data-start=\"1491\" data-end=\"1495\">22</code>).</p>\r\n</li><li data-start=\"1498\" data-end=\"1553\">\r\n<p data-start=\"1500\" data-end=\"1553\"><strong data-start=\"1500\" data-end=\"1522\">Ping Timeout Value</strong>: Set timeout (e.g., <code data-start=\"1543\" data-end=\"1551\">400 ms</code>).</p>\r\n</li><li data-start=\"1554\" data-end=\"1609\">\r\n<p data-start=\"1556\" data-end=\"1609\"><strong data-start=\"1556\" data-end=\"1576\">Ping Retry Count</strong>: Set retry attempts (e.g., <code data-start=\"1604\" data-end=\"1607\">1</code>).</p></li></ul><p><br></p>',0,NULL,'active','2025-08-28 09:02:11','2025-08-28 11:35:38'),(22,'Threshold Template Creation Wizard','threshold-template-creation-wizard','<p data-start=\"154\" data-end=\"282\"><strong data-start=\"195\" data-end=\"229\">1. Threshold Template Creation</strong> → <strong data-start=\"232\" data-end=\"255\">2. General Settings</strong> → <strong data-start=\"258\" data-end=\"282\">3. Data Manipulation</strong></p>\r\n\r\n<h3 data-start=\"289\" data-end=\"326\"><span style=\"font-weight: normal;\">1. Threshold Template Creation</span></h3>\r\n<p data-start=\"328\" data-end=\"353\"><strong data-start=\"328\" data-end=\"353\">Define basic details:</strong></p>\r\n<ul data-start=\"355\" data-end=\"576\"><li data-start=\"355\" data-end=\"422\">\r\n<p data-start=\"357\" data-end=\"422\"><strong data-start=\"357\" data-end=\"372\">Create Type</strong>: Choose threshold type (e.g., Static, Dynamic).</p>\r\n</li><li data-start=\"423\" data-end=\"465\">\r\n<p data-start=\"425\" data-end=\"465\"><strong data-start=\"425\" data-end=\"440\">Device Name</strong>: Select target device.</p>\r\n</li><li data-start=\"466\" data-end=\"515\">\r\n<p data-start=\"468\" data-end=\"515\"><strong data-start=\"468\" data-end=\"482\">Graph Type</strong>: Choose how data is displayed.</p>\r\n</li><li data-start=\"516\" data-end=\"576\">\r\n<p data-start=\"518\" data-end=\"576\"><strong data-start=\"518\" data-end=\"533\">Data Source</strong>: Pick the metric/data source to monitor.</p>\r\n</li></ul>\r\n<blockquote data-start=\"578\" data-end=\"608\">\r\n<p data-start=\"580\" data-end=\"608\">Click <strong data-start=\"586\" data-end=\"596\">Create</strong> to proceed.</p>\r\n</blockquote>\r\n<h3 data-start=\"615\" data-end=\"641\"><span style=\"font-weight: normal;\">2. General Settings</span></h3>\r\n<p data-start=\"643\" data-end=\"684\"><strong data-start=\"643\" data-end=\"684\">Configure threshold logic and alerts:</strong></p>\r\n<ul data-start=\"686\" data-end=\"1222\"><li data-start=\"686\" data-end=\"742\">\r\n<p data-start=\"688\" data-end=\"742\"><strong data-start=\"688\" data-end=\"718\">Enabled at Threshold Level</strong>: Turn ON to activate.</p>\r\n</li><li data-start=\"743\" data-end=\"800\">\r\n<p data-start=\"745\" data-end=\"800\"><strong data-start=\"745\" data-end=\"763\">Threshold Name</strong>: Auto-filled using source details.</p>\r\n</li><li data-start=\"801\" data-end=\"865\">\r\n<p data-start=\"803\" data-end=\"865\"><strong data-start=\"803\" data-end=\"819\">HRULE Colors</strong>: Set graph line colors for warnings/alerts.</p>\r\n</li><li data-start=\"866\" data-end=\"923\">\r\n<p data-start=\"868\" data-end=\"923\"><strong data-start=\"868\" data-end=\"886\">Graph Timespan</strong>: Set time window (e.g., Last Day).</p>\r\n</li><li data-start=\"924\" data-end=\"976\">\r\n<p data-start=\"926\" data-end=\"976\"><strong data-start=\"926\" data-end=\"944\">Threshold Type</strong>: Choose High/Low, Range, etc.</p>\r\n</li><li data-start=\"977\" data-end=\"1084\">\r\n<p data-start=\"979\" data-end=\"1000\"><strong data-start=\"979\" data-end=\"997\">Toggle Options</strong>:</p>\r\n<ul data-start=\"1003\" data-end=\"1084\"><li data-start=\"1003\" data-end=\"1028\">\r\n<p data-start=\"1005\" data-end=\"1028\">Skip Scaling on HRULE</p>\r\n</li><li data-start=\"1031\" data-end=\"1052\">\r\n<p data-start=\"1033\" data-end=\"1052\">Weekend Exemption</p>\r\n</li><li data-start=\"1055\" data-end=\"1084\">\r\n<p data-start=\"1057\" data-end=\"1084\">Disable Restoration Email</p>\r\n</li></ul>\r\n</li><li data-start=\"1085\" data-end=\"1222\">\r\n<p data-start=\"1087\" data-end=\"1108\"><strong data-start=\"1087\" data-end=\"1105\">Alert Settings</strong>:</p>\r\n<ul data-start=\"1111\" data-end=\"1222\"><li data-start=\"1111\" data-end=\"1129\">\r\n<p data-start=\"1113\" data-end=\"1129\">Re-Alert Cycle</p>\r\n</li><li data-start=\"1132\" data-end=\"1157\">\r\n<p data-start=\"1134\" data-end=\"1157\">Acknowledgment Option</p>\r\n</li><li data-start=\"1160\" data-end=\"1199\">\r\n<p data-start=\"1162\" data-end=\"1199\">Warning/Alert Thresholds (High/Low)</p>\r\n</li><li data-start=\"1202\" data-end=\"1222\">\r\n<p data-start=\"1204\" data-end=\"1222\">Breach Durations</p>\r\n</li></ul>\r\n</li></ul>\r\n<blockquote data-start=\"1224\" data-end=\"1253\">\r\n<p data-start=\"1226\" data-end=\"1253\">Click <strong data-start=\"1232\" data-end=\"1240\">Next</strong> to continue.</p>\r\n</blockquote> \r\n<h3 data-start=\"1260\" data-end=\"1287\"><span style=\"font-weight: normal;\">3. Data Manipulation</span></h3>\r\n<p data-start=\"1289\" data-end=\"1315\"><strong data-start=\"1289\" data-end=\"1315\">Adjust display format:</strong></p>\r\n<ul data-start=\"1317\" data-end=\"1520\"><li data-start=\"1317\" data-end=\"1358\">\r\n<p data-start=\"1319\" data-end=\"1358\"><strong data-start=\"1319\" data-end=\"1332\">Data Type</strong>: Exact Value, Avg, etc.</p>\r\n</li><li data-start=\"1359\" data-end=\"1415\">\r\n<p data-start=\"1361\" data-end=\"1415\"><strong data-start=\"1361\" data-end=\"1383\">Force Units Suffix</strong>: (Optional) Add a unit label.</p>\r\n</li><li data-start=\"1416\" data-end=\"1470\">\r\n<p data-start=\"1418\" data-end=\"1470\"><strong data-start=\"1418\" data-end=\"1436\">Decimal Digits</strong>: Auto or custom decimal places.</p>\r\n</li><li data-start=\"1471\" data-end=\"1520\">\r\n<p data-start=\"1473\" data-end=\"1520\"><strong data-start=\"1473\" data-end=\"1487\">Show Units</strong>: Toggle to show unit on display.</p>\r\n</li></ul>\r\n<blockquote data-start=\"1522\" data-end=\"1562\">\r\n<p data-start=\"1524\" data-end=\"1562\">Click <strong data-start=\"1530\" data-end=\"1540\">Submit</strong> to save the template.</p></blockquote><p><br></p>',0,NULL,'active','2025-08-28 11:54:03','2025-08-28 11:54:03'),(23,'New Zone Creation','new-zone-creation','<h3 data-start=\"341\" data-end=\"371\"><span data-start=\"348\" data-end=\"371\" style=\"font-weight: normal;\">1. Site Information</span></h3>\r\n<ul data-start=\"373\" data-end=\"482\"><li data-start=\"373\" data-end=\"482\">\r\n<p data-start=\"375\" data-end=\"482\"><strong data-start=\"375\" data-end=\"388\">Site Name</strong><br data-start=\"388\" data-end=\"391\">\r\nEnter the name for the zone/site you are creating. This should be unique and descriptive.</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"489\" data-end=\"521\"><span data-start=\"495\" data-end=\"521\" style=\"font-weight: normal;\">2. Address Information</span></h3>\r\n<p data-start=\"523\" data-end=\"574\">Fill out the physical address details for the zone:</p>\r\n<ul data-start=\"576\" data-end=\"846\"><li data-start=\"576\" data-end=\"615\">\r\n<p data-start=\"578\" data-end=\"615\"><strong data-start=\"578\" data-end=\"590\">Address1</strong>: Primary address line.</p>\r\n</li><li data-start=\"616\" data-end=\"668\">\r\n<p data-start=\"618\" data-end=\"668\"><strong data-start=\"618\" data-end=\"630\">Address2</strong>: Secondary address line (optional).</p>\r\n</li><li data-start=\"669\" data-end=\"703\">\r\n<p data-start=\"671\" data-end=\"703\"><strong data-start=\"671\" data-end=\"679\">City</strong>: Enter the city name.</p>\r\n</li><li data-start=\"704\" data-end=\"747\">\r\n<p data-start=\"706\" data-end=\"747\"><strong data-start=\"706\" data-end=\"715\">State</strong>: Enter the state or province.</p>\r\n</li><li data-start=\"748\" data-end=\"797\">\r\n<p data-start=\"750\" data-end=\"797\"><strong data-start=\"750\" data-end=\"769\">Postal/Zip Code</strong>: Postal code of the area.</p>\r\n</li><li data-start=\"798\" data-end=\"846\">\r\n<p data-start=\"800\" data-end=\"846\"><strong data-start=\"800\" data-end=\"811\">Country</strong>: Select or enter the country name.</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"853\" data-end=\"889\"><span data-start=\"859\" data-end=\"889\" style=\"font-weight: normal;\">3. Geolocation Information</span></h3>\r\n<p data-start=\"891\" data-end=\"932\">Used for mapping and spatial referencing:</p>\r\n<ul data-start=\"934\" data-end=\"1172\"><li data-start=\"934\" data-end=\"1006\">\r\n<p data-start=\"936\" data-end=\"1006\"><strong data-start=\"936\" data-end=\"948\">Latitude</strong>: Geographical latitude of the zone (in decimal format).</p>\r\n</li><li data-start=\"1007\" data-end=\"1081\">\r\n<p data-start=\"1009\" data-end=\"1081\"><strong data-start=\"1009\" data-end=\"1022\">Longitude</strong>: Geographical longitude of the zone (in decimal format).</p>\r\n</li><li data-start=\"1082\" data-end=\"1172\">\r\n<p data-start=\"1084\" data-end=\"1172\"><strong data-start=\"1084\" data-end=\"1092\">Zoom</strong>: Set zoom level for map display (usually 0–20, where higher is more zoomed-in).</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"1179\" data-end=\"1214\"><span data-start=\"1185\" data-end=\"1214\" style=\"font-weight: normal;\">4. Additional Information</span></h3>\r\n<ul data-start=\"1216\" data-end=\"1363\"><li data-start=\"1216\" data-end=\"1294\">\r\n<p data-start=\"1218\" data-end=\"1294\"><strong data-start=\"1218\" data-end=\"1227\">Notes</strong>: Enter any relevant notes or description for internal reference.</p>\r\n</li><li data-start=\"1295\" data-end=\"1363\">\r\n<p data-start=\"1297\" data-end=\"1363\"><strong data-start=\"1297\" data-end=\"1315\">Alternate Name</strong>: Optional secondary name or alias for the zone.</p>\r\n</li></ul>\r\n\r\n<h3 data-start=\"1370\" data-end=\"1379\"><span style=\"font-weight: normal;\">Tips</span></h3>\r\n<ul data-start=\"1381\" data-end=\"1598\"><li data-start=\"1381\" data-end=\"1463\">\r\n<p data-start=\"1383\" data-end=\"1463\">Ensure <strong data-start=\"1390\" data-end=\"1402\">Latitude</strong> and <strong data-start=\"1407\" data-end=\"1420\">Longitude</strong> are accurate if map integration is used.</p>\r\n</li><li data-start=\"1464\" data-end=\"1537\">\r\n<p data-start=\"1466\" data-end=\"1537\">Use <strong data-start=\"1470\" data-end=\"1478\">Zoom</strong> to control the default map scale when viewing this zone.</p>\r\n</li><li data-start=\"1538\" data-end=\"1598\">\r\n<p data-start=\"1540\" data-end=\"1598\">Always review for completeness before submitting the form.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-28 12:02:00','2025-08-28 12:06:25'),(24,'Network Monitoring','network-monitoring','<h3 data-start=\"267\" data-end=\"289\"><span data-start=\"271\" data-end=\"289\" style=\"font-weight: normal;\">Device List</span></h3>\r\n<p data-start=\"290\" data-end=\"390\">The main grid shows monitored devices, each represented by icons and names. Devices are color-coded:</p>\r\n<ul data-start=\"391\" data-end=\"535\"><li data-start=\"391\" data-end=\"429\">\r\n<p data-start=\"393\" data-end=\"429\"><strong data-start=\"393\" data-end=\"401\">Blue</strong>: Active and online devices.</p>\r\n</li><li data-start=\"430\" data-end=\"478\">\r\n<p data-start=\"432\" data-end=\"478\"><strong data-start=\"432\" data-end=\"439\">Red</strong>: Devices with issues (need attention).</p>\r\n</li><li data-start=\"479\" data-end=\"535\">\r\n<p data-start=\"481\" data-end=\"535\"><strong data-start=\"481\" data-end=\"502\">Gray/Other Colors</strong>: Offline or unavailable devices.</p>\r\n</li></ul>\r\n<h4 data-start=\"537\" data-end=\"558\"><span data-start=\"542\" data-end=\"558\" style=\"font-weight: normal;\">Device Types</span></h4>\r\n<ul data-start=\"559\" data-end=\"888\"><li data-start=\"559\" data-end=\"612\">\r\n<p data-start=\"561\" data-end=\"612\"><strong data-start=\"561\" data-end=\"572\">Routers</strong>: Icons like <strong data-start=\"585\" data-end=\"597\">R2.dcsco</strong>, <strong data-start=\"599\" data-end=\"611\">R3.dcsco</strong>.</p>\r\n</li><li data-start=\"613\" data-end=\"653\">\r\n<p data-start=\"615\" data-end=\"653\"><strong data-start=\"615\" data-end=\"628\">Firewalls</strong>: E.g., <strong data-start=\"636\" data-end=\"652\">Firewall_PUN</strong>.</p>\r\n</li><li data-start=\"654\" data-end=\"689\">\r\n<p data-start=\"656\" data-end=\"689\"><strong data-start=\"656\" data-end=\"668\">Switches</strong>: E.g., <strong data-start=\"676\" data-end=\"688\">R6.dcsco</strong>.</p>\r\n</li><li data-start=\"690\" data-end=\"736\">\r\n<p data-start=\"692\" data-end=\"736\"><strong data-start=\"692\" data-end=\"703\">Servers</strong>: E.g., <strong data-start=\"711\" data-end=\"735\">Infoworks-NMS-Server</strong>.</p>\r\n</li><li data-start=\"737\" data-end=\"774\">\r\n<p data-start=\"739\" data-end=\"774\"><strong data-start=\"739\" data-end=\"746\">PCs</strong>: E.g., <strong data-start=\"754\" data-end=\"773\">DESKTOP-K8IRM3E</strong>.</p>\r\n</li><li data-start=\"775\" data-end=\"815\">\r\n<p data-start=\"777\" data-end=\"815\"><strong data-start=\"777\" data-end=\"789\">Printers</strong>: E.g., <strong data-start=\"797\" data-end=\"814\">PRT-NOI-ADMIN</strong>.</p>\r\n</li><li data-start=\"816\" data-end=\"851\">\r\n<p data-start=\"818\" data-end=\"851\"><strong data-start=\"818\" data-end=\"825\">VMs</strong>: E.g., <strong data-start=\"833\" data-end=\"850\">VM-Ubuntu-NOI</strong>.</p>\r\n</li><li data-start=\"852\" data-end=\"888\">\r\n<p data-start=\"854\" data-end=\"888\"><strong data-start=\"854\" data-end=\"863\">Cloud</strong>: E.g., <strong data-start=\"871\" data-end=\"887\">Firewall-NOI</strong>.</p>\r\n</li></ul>\r\n<h3 data-start=\"890\" data-end=\"914\"><span data-start=\"894\" data-end=\"914\" style=\"font-weight: normal;\">&nbsp;Device Status</span></h3>\r\n<p data-start=\"915\" data-end=\"1012\">Hover over icons to see details like IP address, status (active, inactive, or error), and alerts.</p>\r\n<h3 data-start=\"1014\" data-end=\"1032\"><span data-start=\"1018\" data-end=\"1032\" style=\"font-weight: normal;\">Actions</span></h3>\r\n<ul data-start=\"1033\" data-end=\"1227\"><li data-start=\"1033\" data-end=\"1094\">\r\n<p data-start=\"1035\" data-end=\"1094\"><strong data-start=\"1035\" data-end=\"1053\">Search Devices</strong>: Use the filter to find devices quickly.</p>\r\n</li><li data-start=\"1095\" data-end=\"1161\">\r\n<p data-start=\"1097\" data-end=\"1161\"><strong data-start=\"1097\" data-end=\"1115\">Monitor Status</strong>: Check device color for health (red = issue).</p>\r\n</li><li data-start=\"1162\" data-end=\"1227\">\r\n<p data-start=\"1164\" data-end=\"1227\"><strong data-start=\"1164\" data-end=\"1185\">Click for Details</strong>: Get more info on device status and logs.</p>\r\n</li></ul>\r\n<h3 data-start=\"1229\" data-end=\"1257\"><span data-start=\"1233\" data-end=\"1257\" style=\"font-weight: normal;\">Troubleshooting Tips</span></h3>\r\n<ul data-start=\"1258\" data-end=\"1354\"><li data-start=\"1258\" data-end=\"1305\">\r\n<p data-start=\"1260\" data-end=\"1305\"><strong data-start=\"1260\" data-end=\"1272\">Red Icon</strong>: Device has an issue—check logs.</p>\r\n</li><li data-start=\"1306\" data-end=\"1354\">\r\n<p data-start=\"1308\" data-end=\"1354\"><strong data-start=\"1308\" data-end=\"1324\">Unresponsive</strong>: Check connectivity or power.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-29 10:06:56','2025-08-29 10:06:56'),(25,'Discovery Setting','discovery-setting','<h4 data-start=\"39\" data-end=\"72\"><strong data-start=\"44\" data-end=\"72\">Discovery Settings Table</strong></h4>\r\n<ul data-start=\"73\" data-end=\"809\"><li data-start=\"73\" data-end=\"153\">\r\n<p data-start=\"75\" data-end=\"153\"><strong data-start=\"75\" data-end=\"91\">Network Name</strong>: The name of the discovered network (e.g., <strong data-start=\"135\" data-end=\"151\">InfinityLabs</strong>).</p>\r\n</li><li data-start=\"154\" data-end=\"234\">\r\n<p data-start=\"156\" data-end=\"234\"><strong data-start=\"156\" data-end=\"174\">Data Collector</strong>: The server handling the discovery (e.g., <strong data-start=\"217\" data-end=\"232\">Main Poller</strong>).</p>\r\n</li><li data-start=\"235\" data-end=\"296\">\r\n<p data-start=\"237\" data-end=\"296\"><strong data-start=\"237\" data-end=\"249\">Schedule</strong>: Frequency of the discovery (e.g., <strong data-start=\"285\" data-end=\"294\">Daily</strong>).</p>\r\n</li><li data-start=\"297\" data-end=\"357\">\r\n<p data-start=\"299\" data-end=\"357\"><strong data-start=\"299\" data-end=\"312\">Total IPs</strong>: Number of IPs involved (e.g., <strong data-start=\"344\" data-end=\"355\">765 IPs</strong>).</p>\r\n</li><li data-start=\"358\" data-end=\"422\">\r\n<p data-start=\"360\" data-end=\"422\"><strong data-start=\"360\" data-end=\"370\">Status</strong>: Current status (e.g., <strong data-start=\"394\" data-end=\"402\">Idle</strong>; green means idle).</p>\r\n</li><li data-start=\"423\" data-end=\"495\">\r\n<p data-start=\"425\" data-end=\"495\"><strong data-start=\"425\" data-end=\"442\">Up/SNMP Hosts</strong>: Hosts that are up or responding (e.g., <strong data-start=\"483\" data-end=\"493\">14/108</strong>).</p>\r\n</li><li data-start=\"496\" data-end=\"557\">\r\n<p data-start=\"498\" data-end=\"557\"><strong data-start=\"498\" data-end=\"509\">Threads</strong>: Number of threads used (e.g., <strong data-start=\"541\" data-end=\"555\">10 threads</strong>).</p>\r\n</li><li data-start=\"558\" data-end=\"630\">\r\n<p data-start=\"560\" data-end=\"630\"><strong data-start=\"560\" data-end=\"577\">Last Run Time</strong>: Duration of the last discovery (e.g., <strong data-start=\"617\" data-end=\"628\">391.95s</strong>).</p>\r\n</li><li data-start=\"631\" data-end=\"718\">\r\n<p data-start=\"633\" data-end=\"718\"><strong data-start=\"633\" data-end=\"647\">Next Start</strong>: When the next discovery is scheduled (e.g., <strong data-start=\"693\" data-end=\"716\">2025-05-16 20:00:00</strong>).</p>\r\n</li><li data-start=\"719\" data-end=\"809\">\r\n<p data-start=\"721\" data-end=\"809\"><strong data-start=\"721\" data-end=\"737\">Last Started</strong>: Timestamp of the last discovery start (e.g., <strong data-start=\"784\" data-end=\"807\">2025-05-14 20:02:19</strong>).</p>\r\n</li></ul>\r\n<h4 data-start=\"811\" data-end=\"833\"><strong data-start=\"816\" data-end=\"833\">Actions Panel</strong></h4><ul data-start=\"834\" data-end=\"949\"><li data-start=\"834\" data-end=\"907\">\r\n<p data-start=\"836\" data-end=\"907\"><strong data-start=\"836\" data-end=\"856\">Choose an Action</strong>: Dropdown for actions like edit, delete, or pause.</p>\r\n</li><li data-start=\"908\" data-end=\"949\">\r\n<p data-start=\"910\" data-end=\"949\"><strong data-start=\"910\" data-end=\"919\">+ Add</strong>: Create a new discovery task.</p></li></ul><h4 data-start=\"1324\" data-end=\"1349\"><strong data-start=\"1329\" data-end=\"1348\">Troubleshooting</strong>:</h4>\r\n<ul data-start=\"1350\" data-end=\"1614\"><li data-start=\"1350\" data-end=\"1431\">\r\n<p data-start=\"1352\" data-end=\"1431\"><strong data-start=\"1352\" data-end=\"1367\">Idle Status</strong>: If <strong data-start=\"1372\" data-end=\"1380\">Idle</strong>, verify the schedule or trigger the task manually.</p>\r\n</li><li data-start=\"1432\" data-end=\"1517\">\r\n<p data-start=\"1434\" data-end=\"1517\"><strong data-start=\"1434\" data-end=\"1452\">Low SNMP Hosts</strong>: Ensure SNMP is enabled on devices and the network is reachable.</p>\r\n</li><li data-start=\"1518\" data-end=\"1614\">\r\n<p data-start=\"1520\" data-end=\"1614\"><strong data-start=\"1520\" data-end=\"1537\">Long Run Time</strong>: Consider reducing scope or increasing threads if the last run time is long.</p>\r\n</li></ul>\r\n<p data-start=\"1616\" data-end=\"1688\" data-is-last-node=\"\" data-is-only-node=\"\">This guide helps manage and monitor network discovery tasks efficiently.</p><p><br></p>',0,NULL,'active','2025-08-29 10:29:41','2025-08-29 11:28:56'),(26,'Host Device Dashboard','host-device-dashboard','<h3 data-start=\"117\" data-end=\"143\"><strong data-start=\"121\" data-end=\"143\">Host Devices Table</strong></h3><ul data-start=\"144\" data-end=\"663\"><li data-start=\"144\" data-end=\"212\">\r\n<p data-start=\"146\" data-end=\"212\"><strong data-start=\"146\" data-end=\"158\">Hostname</strong>: The device’s name (e.g., <strong data-start=\"185\" data-end=\"196\">testOne</strong>, <strong data-start=\"198\" data-end=\"210\">R6.dcsco</strong>).</p>\r\n</li><li data-start=\"213\" data-end=\"247\">\r\n<p data-start=\"215\" data-end=\"247\"><strong data-start=\"215\" data-end=\"229\">IP Address</strong>: The device\'s IP.</p>\r\n</li><li data-start=\"248\" data-end=\"283\">\r\n<p data-start=\"250\" data-end=\"283\"><strong data-start=\"250\" data-end=\"256\">ID</strong>: Unique device identifier.</p>\r\n</li><li data-start=\"284\" data-end=\"358\">\r\n<p data-start=\"286\" data-end=\"358\"><strong data-start=\"286\" data-end=\"296\">Status</strong>: Indicates if the device is <strong data-start=\"325\" data-end=\"331\">Up</strong> (green) or <strong data-start=\"343\" data-end=\"351\">Down</strong> (red).</p>\r\n</li><li data-start=\"359\" data-end=\"431\">\r\n<p data-start=\"361\" data-end=\"431\"><strong data-start=\"361\" data-end=\"371\">Uptime</strong>: Time the device has been up or down (e.g., <strong data-start=\"416\" data-end=\"429\">0d 2h 21m</strong>).</p>\r\n</li><li data-start=\"432\" data-end=\"503\">\r\n<p data-start=\"434\" data-end=\"503\"><strong data-start=\"434\" data-end=\"453\">Poll Time (min)</strong>: Frequency of device checks (e.g., <strong data-start=\"489\" data-end=\"501\">1.14 min</strong>).</p>\r\n</li><li data-start=\"504\" data-end=\"561\">\r\n<p data-start=\"506\" data-end=\"561\"><strong data-start=\"506\" data-end=\"522\">Current (ms)</strong>: Device response time in milliseconds.</p>\r\n</li><li data-start=\"562\" data-end=\"604\">\r\n<p data-start=\"564\" data-end=\"604\"><strong data-start=\"564\" data-end=\"580\">Average (ms)</strong>: Average response time.</p>\r\n</li><li data-start=\"605\" data-end=\"663\">\r\n<p data-start=\"607\" data-end=\"663\"><strong data-start=\"607\" data-end=\"623\">Availability</strong>: Percentage of uptime (e.g., <strong data-start=\"653\" data-end=\"661\">100%</strong>).</p></li></ul><h3 data-start=\"670\" data-end=\"691\"><strong data-start=\"674\" data-end=\"691\">Actions Panel</strong></h3>\r\n<ul data-start=\"692\" data-end=\"920\"><li data-start=\"692\" data-end=\"751\">\r\n<p data-start=\"694\" data-end=\"751\"><strong data-start=\"694\" data-end=\"714\">Choose an action</strong>: Select actions like edit or delete.</p>\r\n</li><li data-start=\"752\" data-end=\"792\">\r\n<p data-start=\"754\" data-end=\"792\"><strong data-start=\"754\" data-end=\"760\">Go</strong>: Initiates the selected action.</p>\r\n</li><li data-start=\"793\" data-end=\"840\">\r\n<p data-start=\"795\" data-end=\"840\"><strong data-start=\"795\" data-end=\"805\">Filter</strong>: Filter devices based on criteria.</p>\r\n</li><li data-start=\"841\" data-end=\"884\">\r\n<p data-start=\"843\" data-end=\"884\"><strong data-start=\"843\" data-end=\"853\">Export</strong>: Export device data to a file.</p>\r\n</li><li data-start=\"885\" data-end=\"920\">\r\n<p data-start=\"887\" data-end=\"920\"><strong data-start=\"887\" data-end=\"896\">+ Add</strong>: Add a new host device</p></li></ul><h3 data-start=\"1221\" data-end=\"1244\"><strong data-start=\"1225\" data-end=\"1244\">Troubleshooting</strong></h3>\r\n<ul data-start=\"1245\" data-end=\"1482\"><li data-start=\"1245\" data-end=\"1312\">\r\n<p data-start=\"1247\" data-end=\"1312\"><strong data-start=\"1247\" data-end=\"1262\">Down Status</strong>: Check if the device is powered on and connected.</p>\r\n</li><li data-start=\"1313\" data-end=\"1394\">\r\n<p data-start=\"1315\" data-end=\"1394\"><strong data-start=\"1315\" data-end=\"1333\">High Poll Time</strong>: Investigate potential network issues or device performance.</p>\r\n</li><li data-start=\"1395\" data-end=\"1482\">\r\n<p data-start=\"1397\" data-end=\"1482\"><strong data-start=\"1397\" data-end=\"1417\">Low Availability</strong>: Devices with low availability might indicate frequent downtime.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-29 11:40:50','2025-08-29 11:46:18'),(27,'Threshold Configuration','threshold-configuration','<h3 data-start=\"150\" data-end=\"187\"><strong data-start=\"154\" data-end=\"187\">Threshold Configuration Table</strong></h3>\r\n<p data-start=\"188\" data-end=\"286\">This table displays the list of all configured thresholds, including key metrics and their status:</p>\r\n<h4 data-start=\"288\" data-end=\"314\"><strong data-start=\"293\" data-end=\"313\">Columns Overview</strong>:</h4>\r\n<ul data-start=\"315\" data-end=\"1526\"><li data-start=\"315\" data-end=\"375\">\r\n<p data-start=\"317\" data-end=\"375\"><strong data-start=\"317\" data-end=\"323\">ID</strong>: Unique identifier for the threshold configuration.</p>\r\n</li><li data-start=\"376\" data-end=\"450\">\r\n<p data-start=\"378\" data-end=\"450\"><strong data-start=\"378\" data-end=\"386\">Name</strong>: The name or label for the threshold (e.g., <strong data-start=\"431\" data-end=\"448\">VM-Ubuntu-NOI</strong>).</p>\r\n</li><li data-start=\"451\" data-end=\"540\">\r\n<p data-start=\"453\" data-end=\"540\"><strong data-start=\"453\" data-end=\"464\">Enabled</strong>: Indicates whether the threshold is enabled (<strong data-start=\"510\" data-end=\"517\">Yes</strong>) or disabled (<strong data-start=\"532\" data-end=\"538\">No</strong>).</p>\r\n</li><li data-start=\"541\" data-end=\"599\">\r\n<p data-start=\"543\" data-end=\"599\"><strong data-start=\"543\" data-end=\"551\">Type</strong>: The type of threshold, typically <strong data-start=\"586\" data-end=\"598\">High/Low</strong>.</p>\r\n</li><li data-start=\"600\" data-end=\"675\">\r\n<p data-start=\"602\" data-end=\"675\"><strong data-start=\"602\" data-end=\"614\">Graph ID</strong>: The identifier for the graph associated with the threshold.</p>\r\n</li><li data-start=\"676\" data-end=\"790\">\r\n<p data-start=\"678\" data-end=\"790\"><strong data-start=\"678\" data-end=\"688\">DSName</strong>: The data source name linked to the threshold configuration (e.g., <strong data-start=\"756\" data-end=\"772\">polling_time</strong>, <strong data-start=\"774\" data-end=\"788\">traffic_in</strong>).</p>\r\n</li><li data-start=\"791\" data-end=\"853\">\r\n<p data-start=\"793\" data-end=\"853\"><strong data-start=\"793\" data-end=\"804\">Current</strong>: The current value or measurement of the metric.</p>\r\n</li><li data-start=\"854\" data-end=\"910\">\r\n<p data-start=\"856\" data-end=\"910\"><strong data-start=\"856\" data-end=\"864\">High</strong>: The high threshold value set for the metric.</p>\r\n</li><li data-start=\"911\" data-end=\"965\">\r\n<p data-start=\"913\" data-end=\"965\"><strong data-start=\"913\" data-end=\"920\">Low</strong>: The low threshold value set for the metric.</p>\r\n</li><li data-start=\"966\" data-end=\"1071\">\r\n<p data-start=\"968\" data-end=\"1071\"><strong data-start=\"968\" data-end=\"980\">Duration</strong>: The duration for which the metric must exceed the threshold before an alert is triggered.</p>\r\n</li><li data-start=\"1072\" data-end=\"1143\">\r\n<p data-start=\"1074\" data-end=\"1143\"><strong data-start=\"1074\" data-end=\"1084\">Repeat</strong>: Indicates if the threshold is repeated (e.g., <strong data-start=\"1132\" data-end=\"1141\">Never</strong>).</p>\r\n</li><li data-start=\"1144\" data-end=\"1228\">\r\n<p data-start=\"1146\" data-end=\"1228\"><strong data-start=\"1146\" data-end=\"1159\">Triggered</strong>: Shows whether the threshold has been triggered (<strong data-start=\"1209\" data-end=\"1216\">Yes</strong> or <strong data-start=\"1220\" data-end=\"1226\">No</strong>).</p>\r\n</li><li data-start=\"1229\" data-end=\"1334\">\r\n<p data-start=\"1231\" data-end=\"1334\"><strong data-start=\"1231\" data-end=\"1243\">In State</strong>: Indicates how long the threshold has been in the current state (e.g., <strong data-start=\"1315\" data-end=\"1332\">Since Created</strong>).</p>\r\n</li><li data-start=\"1335\" data-end=\"1421\">\r\n<p data-start=\"1337\" data-end=\"1421\"><strong data-start=\"1337\" data-end=\"1350\">Templated</strong>: Indicates if the threshold is part of a template (<strong data-start=\"1402\" data-end=\"1409\">Yes</strong> or <strong data-start=\"1413\" data-end=\"1419\">No</strong>).</p>\r\n</li><li data-start=\"1422\" data-end=\"1526\">\r\n<p data-start=\"1424\" data-end=\"1526\"><strong data-start=\"1424\" data-end=\"1440\">Ack Required</strong>: Indicates whether acknowledgment is required for this threshold (<strong data-start=\"1507\" data-end=\"1514\">Yes</strong> or <strong data-start=\"1518\" data-end=\"1524\">No</strong>).</p></li></ul><h3 data-start=\"1533\" data-end=\"1554\"><strong data-start=\"1537\" data-end=\"1554\">Actions Panel</strong></h3>\r\n<ul data-start=\"1555\" data-end=\"1876\"><li data-start=\"1555\" data-end=\"1635\">\r\n<p data-start=\"1557\" data-end=\"1635\"><strong data-start=\"1557\" data-end=\"1577\">Choose an action</strong>: Dropdown to select actions like edit, delete, or export.</p>\r\n</li><li data-start=\"1636\" data-end=\"1676\">\r\n<p data-start=\"1638\" data-end=\"1676\"><strong data-start=\"1638\" data-end=\"1644\">Go</strong>: Initiates the selected action.</p>\r\n</li><li data-start=\"1677\" data-end=\"1746\">\r\n<p data-start=\"1679\" data-end=\"1746\"><strong data-start=\"1679\" data-end=\"1689\">Import</strong>: Import a threshold configuration from an external file.</p>\r\n</li><li data-start=\"1747\" data-end=\"1807\">\r\n<p data-start=\"1749\" data-end=\"1807\"><strong data-start=\"1749\" data-end=\"1759\">Export</strong>: Export threshold configuration data to a file.</p>\r\n</li><li data-start=\"1808\" data-end=\"1876\">\r\n<p data-start=\"1810\" data-end=\"1876\"><strong data-start=\"1810\" data-end=\"1819\">+ Add</strong>: Click this button to add a new threshold configuration</p></li></ul><h3 data-start=\"1883\" data-end=\"1906\"><strong data-start=\"1887\" data-end=\"1905\">Common Actions</strong>:</h3>\r\n<ul data-start=\"1907\" data-end=\"2225\"><li data-start=\"1907\" data-end=\"1992\">\r\n<p data-start=\"1909\" data-end=\"1992\"><strong data-start=\"1909\" data-end=\"1919\">Search</strong>: Use the <strong data-start=\"1929\" data-end=\"1944\">Search here</strong> bar to find a specific threshold configuration.</p>\r\n</li><li data-start=\"1993\" data-end=\"2089\">\r\n<p data-start=\"1995\" data-end=\"2089\"><strong data-start=\"1995\" data-end=\"2010\">Edit/Delete</strong>: Select one or more thresholds and use <strong data-start=\"2050\" data-end=\"2070\">Choose an action</strong> to edit or delete.</p>\r\n</li><li data-start=\"2090\" data-end=\"2157\">\r\n<p data-start=\"2092\" data-end=\"2157\"><strong data-start=\"2092\" data-end=\"2099\">Add</strong>: Click <strong data-start=\"2107\" data-end=\"2116\">+ Add</strong> to create a new threshold configuration.</p>\r\n</li><li data-start=\"2158\" data-end=\"2225\">\r\n<p data-start=\"2160\" data-end=\"2225\"><strong data-start=\"2160\" data-end=\"2170\">Export</strong>: Export the list of thresholds for backup or analysis.</p></li></ul><h3 data-start=\"2232\" data-end=\"2261\"><strong data-start=\"2236\" data-end=\"2260\">Troubleshooting Tips</strong>:</h3>\r\n<ul data-start=\"2262\" data-end=\"2638\"><li data-start=\"2262\" data-end=\"2421\">\r\n<p data-start=\"2264\" data-end=\"2421\"><strong data-start=\"2264\" data-end=\"2288\">Triggered Thresholds</strong>: If a threshold shows as <strong data-start=\"2314\" data-end=\"2327\">Triggered</strong>, check the current metric values and adjust the threshold if necessary to avoid false alarms.</p>\r\n</li><li data-start=\"2422\" data-end=\"2532\">\r\n<p data-start=\"2424\" data-end=\"2532\"><strong data-start=\"2424\" data-end=\"2446\">Enabled Thresholds</strong>: Ensure that the threshold is enabled for it to actively monitor the desired metrics.</p>\r\n</li><li data-start=\"2533\" data-end=\"2638\">\r\n<p data-start=\"2535\" data-end=\"2638\"><strong data-start=\"2535\" data-end=\"2554\">High/Low Values</strong>: Review the <strong data-start=\"2567\" data-end=\"2575\">High</strong> and <strong data-start=\"2580\" data-end=\"2587\">Low</strong> values for accuracy to ensure proper thresholding.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-29 11:51:56','2025-08-29 11:52:24'),(28,'Telemetry Graphs','telemetry-graphs','<h3 data-start=\"146\" data-end=\"177\"><strong data-start=\"150\" data-end=\"177\">Telemetry Data Table</strong></h3>\r\n<p data-start=\"178\" data-end=\"280\">The table displays the telemetry data for each device and service. Here\'s what each column represents:</p>\r\n<h4 data-start=\"282\" data-end=\"308\"><strong data-start=\"287\" data-end=\"307\">Columns Overview</strong>:</h4>\r\n<ul data-start=\"309\" data-end=\"1030\"><li data-start=\"309\" data-end=\"403\">\r\n<p data-start=\"311\" data-end=\"403\"><strong data-start=\"311\" data-end=\"324\">Host Name</strong>: The name of the monitored device (e.g., <strong data-start=\"366\" data-end=\"383\">192.168.1.254</strong>, <strong data-start=\"385\" data-end=\"401\">Firewall_PUN</strong>).</p>\r\n</li><li data-start=\"404\" data-end=\"499\">\r\n<p data-start=\"406\" data-end=\"499\"><strong data-start=\"406\" data-end=\"422\">Service Name</strong>: The specific service being monitored (e.g., <strong data-start=\"468\" data-end=\"484\">Availability</strong>, <strong data-start=\"486\" data-end=\"497\">Traffic</strong>).</p>\r\n</li><li data-start=\"500\" data-end=\"597\">\r\n<p data-start=\"502\" data-end=\"597\"><strong data-start=\"502\" data-end=\"512\">Status</strong>: The current status of the service (e.g., <strong data-start=\"555\" data-end=\"561\">Up</strong>, <strong data-start=\"563\" data-end=\"571\">Down</strong>, <strong data-start=\"573\" data-end=\"582\">Alert</strong>, <strong data-start=\"584\" data-end=\"595\">Warning</strong>).</p>\r\n</li><li data-start=\"598\" data-end=\"688\">\r\n<p data-start=\"600\" data-end=\"688\"><strong data-start=\"600\" data-end=\"617\">Current Value</strong>: The current value of the metric being tracked (e.g., <strong data-start=\"672\" data-end=\"686\">100.000000</strong>).</p>\r\n</li><li data-start=\"689\" data-end=\"792\">\r\n<p data-start=\"691\" data-end=\"792\"><strong data-start=\"691\" data-end=\"718\">Threshold Enable Status</strong>: Indicates whether thresholds are enabled for this metric (e.g., <strong data-start=\"784\" data-end=\"790\">on</strong>).</p>\r\n</li><li data-start=\"793\" data-end=\"923\">\r\n<p data-start=\"795\" data-end=\"923\"><strong data-start=\"795\" data-end=\"819\">Trigger/Polling Time</strong>: The last time the data was polled or when the threshold was triggered (e.g., <strong data-start=\"898\" data-end=\"921\">2025-05-15 14:20:16</strong>).</p>\r\n</li><li data-start=\"924\" data-end=\"1030\">\r\n<p data-start=\"926\" data-end=\"1030\"><strong data-start=\"926\" data-end=\"934\">View</strong>: A link to view detailed telemetry data or graphs for each service (indicated by the eye icon).</p></li></ul><h3 data-start=\"1037\" data-end=\"1061\"><strong data-start=\"1041\" data-end=\"1061\">Actions Panel</strong></h3>\r\n<ul data-start=\"1062\" data-end=\"1166\"><li data-start=\"1062\" data-end=\"1166\">\r\n<p data-start=\"1064\" data-end=\"1166\"><strong data-start=\"1064\" data-end=\"1074\">Filter</strong>: Click the <strong data-start=\"1086\" data-end=\"1096\">Filter</strong> button to apply filters and narrow down the displayed telemetry data.</p></li></ul><h3 data-start=\"1496\" data-end=\"1522\"><strong data-start=\"1500\" data-end=\"1521\">Status Indicators</strong>:</h3>\r\n<ul data-start=\"1523\" data-end=\"1842\"><li data-start=\"1523\" data-end=\"1594\">\r\n<p data-start=\"1525\" data-end=\"1594\"><strong data-start=\"1525\" data-end=\"1531\">Up</strong>: Indicates the service is functioning correctly (green arrow).</p>\r\n</li><li data-start=\"1595\" data-end=\"1649\">\r\n<p data-start=\"1597\" data-end=\"1649\"><strong data-start=\"1597\" data-end=\"1607\">Normal</strong>: Service is operating as expected (blue).</p>\r\n</li><li data-start=\"1650\" data-end=\"1713\">\r\n<p data-start=\"1652\" data-end=\"1713\"><strong data-start=\"1652\" data-end=\"1662\">Notice</strong>: Service is showing a non-critical issue (yellow).</p>\r\n</li><li data-start=\"1714\" data-end=\"1774\">\r\n<p data-start=\"1716\" data-end=\"1774\"><strong data-start=\"1716\" data-end=\"1725\">Alert</strong>: Service has reached a critical threshold (red).</p>\r\n</li><li data-start=\"1775\" data-end=\"1842\">\r\n<p data-start=\"1777\" data-end=\"1842\"><strong data-start=\"1777\" data-end=\"1788\">Warning</strong>: Service has reached a cautionary threshold (orange).</p></li></ul><h3 data-start=\"1849\" data-end=\"1878\"><strong data-start=\"1853\" data-end=\"1877\">Troubleshooting Tips</strong>:</h3>\r\n<ul data-start=\"1879\" data-end=\"2249\"><li data-start=\"1879\" data-end=\"2028\">\r\n<p data-start=\"1881\" data-end=\"2028\"><strong data-start=\"1881\" data-end=\"1897\">Alert Status</strong>: If a service shows <strong data-start=\"1918\" data-end=\"1927\">Alert</strong>, investigate the <strong data-start=\"1945\" data-end=\"1962\">Current Value</strong> and adjust the threshold settings or check for underlying issues.</p>\r\n</li><li data-start=\"2029\" data-end=\"2128\">\r\n<p data-start=\"2031\" data-end=\"2128\"><strong data-start=\"2031\" data-end=\"2045\">Thresholds</strong>: Ensure thresholds are correctly set to trigger notifications only when necessary.</p>\r\n</li><li data-start=\"2129\" data-end=\"2249\">\r\n<p data-start=\"2131\" data-end=\"2249\"><strong data-start=\"2131\" data-end=\"2152\">Status Monitoring</strong>: Regularly monitor <strong data-start=\"2172\" data-end=\"2178\">Up</strong> and <strong data-start=\"2183\" data-end=\"2191\">Down</strong> statuses to keep track of any device or service failures.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-29 11:59:41','2025-08-29 12:00:01'),(29,'Alarm Logs','alarm-logs','<h3 data-start=\"161\" data-end=\"188\"><strong data-start=\"165\" data-end=\"188\">Alarm Logs Table</strong></h3>\r\n<p data-start=\"189\" data-end=\"291\">The table shows detailed information about triggered alarms, including relevant device and event data.</p>\r\n<h4 data-start=\"293\" data-end=\"319\"><strong data-start=\"298\" data-end=\"318\">Columns Overview</strong>:</h4>\r\n<ul data-start=\"320\" data-end=\"915\"><li data-start=\"320\" data-end=\"425\">\r\n<p data-start=\"322\" data-end=\"425\"><strong data-start=\"322\" data-end=\"332\">Device</strong>: The name of the device where the alarm occurred (e.g., <strong data-start=\"389\" data-end=\"405\">INF-PUN-S-01</strong>, <strong data-start=\"407\" data-end=\"423\">Firewall-NOI</strong>).</p>\r\n</li><li data-start=\"426\" data-end=\"485\">\r\n<p data-start=\"428\" data-end=\"485\"><strong data-start=\"428\" data-end=\"436\">Time</strong>: The date and time when the alarm was triggered.</p>\r\n</li><li data-start=\"486\" data-end=\"571\">\r\n<p data-start=\"488\" data-end=\"571\"><strong data-start=\"488\" data-end=\"496\">Type</strong>: Indicates the threshold type for the alarm (e.g., <strong data-start=\"548\" data-end=\"560\">High/Low</strong>, <strong data-start=\"562\" data-end=\"569\">N/A</strong>).</p>\r\n</li><li data-start=\"572\" data-end=\"746\">\r\n<p data-start=\"574\" data-end=\"746\"><strong data-start=\"574\" data-end=\"595\">Event Description</strong>: A description of the event, including details about the metric that triggered the alarm (e.g., <strong data-start=\"692\" data-end=\"744\">WARNING: went above Threshold of 500 with 504.77</strong>).</p>\r\n</li><li data-start=\"747\" data-end=\"822\">\r\n<p data-start=\"749\" data-end=\"822\"><strong data-start=\"749\" data-end=\"764\">Alarm Value</strong>: The predefined threshold value that triggered the alarm.</p>\r\n</li><li data-start=\"823\" data-end=\"915\">\r\n<p data-start=\"825\" data-end=\"915\"><strong data-start=\"825\" data-end=\"843\">Measured Value</strong>: The actual measured value that triggered the alarm (e.g., <strong data-start=\"903\" data-end=\"913\">504.77</strong>).</p></li></ul><h3 data-start=\"922\" data-end=\"953\"><strong data-start=\"926\" data-end=\"952\">Alarm Status Colors</strong>:</h3>\r\n<ul data-start=\"954\" data-end=\"1276\"><li data-start=\"954\" data-end=\"1064\">\r\n<p data-start=\"956\" data-end=\"1064\"><strong data-start=\"956\" data-end=\"966\">Yellow</strong>: The alarm is a <strong data-start=\"983\" data-end=\"994\">Warning</strong>, indicating that the metric exceeded a threshold but is not critical.</p>\r\n</li><li data-start=\"1065\" data-end=\"1180\">\r\n<p data-start=\"1067\" data-end=\"1180\"><strong data-start=\"1067\" data-end=\"1074\">Red</strong>: The alarm is <strong data-start=\"1089\" data-end=\"1101\">Critical</strong>, indicating that the metric far exceeded the threshold and requires attention.</p>\r\n</li><li data-start=\"1181\" data-end=\"1276\">\r\n<p data-start=\"1183\" data-end=\"1276\"><strong data-start=\"1183\" data-end=\"1191\">Pink</strong>: <strong data-start=\"1193\" data-end=\"1219\">Threshold Baseline Log</strong>, indicating a baseline event without a critical trigger.</p></li></ul><h3 data-start=\"1283\" data-end=\"1307\"><strong data-start=\"1287\" data-end=\"1307\">Actions Panel</strong></h3><ul data-start=\"1308\" data-end=\"1541\"><li data-start=\"1308\" data-end=\"1405\">\r\n<p data-start=\"1310\" data-end=\"1405\"><strong data-start=\"1310\" data-end=\"1330\">Choose an action</strong>: Dropdown menu to select actions like acknowledging or clearing the alarm.</p>\r\n</li><li data-start=\"1406\" data-end=\"1445\">\r\n<p data-start=\"1408\" data-end=\"1445\"><strong data-start=\"1408\" data-end=\"1414\">Go</strong>: Executes the selected action.</p>\r\n</li><li data-start=\"1446\" data-end=\"1541\">\r\n<p data-start=\"1448\" data-end=\"1541\"><strong data-start=\"1448\" data-end=\"1458\">Filter</strong>: Filter the logs based on specific criteria (e.g., device, event type, or status).</p></li></ul><h3 data-start=\"1935\" data-end=\"1964\"><strong data-start=\"1939\" data-end=\"1963\">Troubleshooting Tips</strong>:</h3>\r\n<ul data-start=\"1965\" data-end=\"2402\"><li data-start=\"1965\" data-end=\"2136\">\r\n<p data-start=\"1967\" data-end=\"2136\"><strong data-start=\"1967\" data-end=\"1985\">Warning Alerts</strong>: Review the event description and check the device to verify if adjustments are necessary (e.g., lowering thresholds or improving device performance).</p>\r\n</li><li data-start=\"2137\" data-end=\"2281\">\r\n<p data-start=\"2139\" data-end=\"2281\"><strong data-start=\"2139\" data-end=\"2158\">Critical Alerts</strong>: Address critical alarms immediately by reviewing the device’s performance and addressing the issue that caused the alarm.</p>\r\n</li><li data-start=\"2282\" data-end=\"2402\">\r\n<p data-start=\"2284\" data-end=\"2402\"><strong data-start=\"2284\" data-end=\"2301\">Baseline Logs</strong>: Baseline events are informational and may not require action unless they indicate recurring issues.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-29 12:04:22','2026-01-30 12:23:44'),(30,'Device Zones','device-zones','<h3 data-start=\"174\" data-end=\"203\"><strong data-start=\"178\" data-end=\"203\">Device Zones Table</strong></h3>\r\n<p data-start=\"204\" data-end=\"302\">The table displays a list of configured device zones, including the relevant location information.</p>\r\n<h4 data-start=\"304\" data-end=\"330\"><strong data-start=\"309\" data-end=\"329\">Columns Overview</strong>:</h4>\r\n<ul data-start=\"331\" data-end=\"841\"><li data-start=\"331\" data-end=\"383\">\r\n<p data-start=\"333\" data-end=\"383\"><strong data-start=\"333\" data-end=\"339\">ID</strong>: The unique identifier for the device zone.</p>\r\n</li><li data-start=\"384\" data-end=\"456\">\r\n<p data-start=\"386\" data-end=\"456\"><strong data-start=\"386\" data-end=\"399\">Site Name</strong>: The name of the device zone (e.g., <strong data-start=\"436\" data-end=\"444\">Edge</strong>, <strong data-start=\"446\" data-end=\"454\">Core</strong>).</p>\r\n</li><li data-start=\"457\" data-end=\"519\">\r\n<p data-start=\"459\" data-end=\"519\"><strong data-start=\"459\" data-end=\"477\">Alternate Name</strong>: An optional alternate name for the zone.</p>\r\n</li><li data-start=\"520\" data-end=\"589\">\r\n<p data-start=\"522\" data-end=\"589\"><strong data-start=\"522\" data-end=\"530\">City</strong>: The city where the device zone is located (if available).</p>\r\n</li><li data-start=\"590\" data-end=\"660\">\r\n<p data-start=\"592\" data-end=\"660\"><strong data-start=\"592\" data-end=\"601\">State</strong>: The state or province of the device zone (if applicable).</p>\r\n</li><li data-start=\"661\" data-end=\"729\">\r\n<p data-start=\"663\" data-end=\"729\"><strong data-start=\"663\" data-end=\"674\">Country</strong>: The country where the zone is located (if available).</p>\r\n</li><li data-start=\"730\" data-end=\"784\">\r\n<p data-start=\"732\" data-end=\"784\"><strong data-start=\"732\" data-end=\"744\">Latitude</strong>: The geographical latitude of the zone.</p>\r\n</li><li data-start=\"785\" data-end=\"841\">\r\n<p data-start=\"787\" data-end=\"841\"><strong data-start=\"787\" data-end=\"800\">Longitude</strong>: The geographical longitude of the zone.</p></li></ul><h3 data-start=\"848\" data-end=\"872\"><strong data-start=\"852\" data-end=\"872\">Actions Panel</strong></h3><ul data-start=\"873\" data-end=\"1074\"><li data-start=\"873\" data-end=\"989\">\r\n<p data-start=\"875\" data-end=\"989\"><strong data-start=\"875\" data-end=\"895\">Choose an action</strong>: Dropdown menu to perform actions like editing, deleting, or exporting selected device zones.</p>\r\n</li><li data-start=\"990\" data-end=\"1029\">\r\n<p data-start=\"992\" data-end=\"1029\"><strong data-start=\"992\" data-end=\"998\">Go</strong>: Executes the selected action.</p>\r\n</li><li data-start=\"1030\" data-end=\"1074\">\r\n<p data-start=\"1032\" data-end=\"1074\"><strong data-start=\"1032\" data-end=\"1041\">+ Add</strong>: Click to add a new device zone.</p></li></ul><h3 data-start=\"1346\" data-end=\"1375\"><strong data-start=\"1350\" data-end=\"1374\">Troubleshooting Tips</strong>:</h3>\r\n<ul data-start=\"1376\" data-end=\"1720\"><li data-start=\"1376\" data-end=\"1574\">\r\n<p data-start=\"1378\" data-end=\"1574\"><strong data-start=\"1378\" data-end=\"1403\">Missing Location Data</strong>: If <strong data-start=\"1408\" data-end=\"1416\">City</strong>, <strong data-start=\"1418\" data-end=\"1427\">State</strong>, <strong data-start=\"1429\" data-end=\"1440\">Country</strong>, <strong data-start=\"1442\" data-end=\"1454\">Latitude</strong>, or <strong data-start=\"1459\" data-end=\"1472\">Longitude</strong> values are missing, check the zone settings to ensure the location information is properly filled in.</p>\r\n</li><li data-start=\"1575\" data-end=\"1720\">\r\n<p data-start=\"1577\" data-end=\"1720\"><strong data-start=\"1577\" data-end=\"1595\">Multiple Zones</strong>: If you need to assign devices to a specific zone, ensure each device is linked to the correct zone for accurate monitoring.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-29 12:11:14','2025-08-29 12:11:14'),(31,'Discovered Devices','discovered-devices','<h3 data-start=\"136\" data-end=\"171\"><strong data-start=\"140\" data-end=\"171\">Discovered Devices Table</strong></h3>\r\n<p data-start=\"172\" data-end=\"259\">The table lists the discovered devices, showing detailed information about each device.</p>\r\n<h4 data-start=\"261\" data-end=\"287\"><strong data-start=\"266\" data-end=\"286\">Columns Overview</strong>:</h4>\r\n<ul data-start=\"288\" data-end=\"994\"><li data-start=\"288\" data-end=\"366\">\r\n<p data-start=\"290\" data-end=\"366\"><strong data-start=\"290\" data-end=\"302\">HostName</strong>: The device’s hostname (e.g., <strong data-start=\"333\" data-end=\"349\">Not Detected</strong>, <strong data-start=\"351\" data-end=\"364\">bumblebee</strong>).</p>\r\n</li><li data-start=\"367\" data-end=\"449\">\r\n<p data-start=\"369\" data-end=\"449\"><strong data-start=\"369\" data-end=\"383\">IP Address</strong>: The IP address assigned to the device (e.g., <strong data-start=\"430\" data-end=\"447\">192.168.1.183</strong>).</p>\r\n</li><li data-start=\"450\" data-end=\"513\">\r\n<p data-start=\"452\" data-end=\"513\"><strong data-start=\"452\" data-end=\"464\">Location</strong>: The physical or logical location of the device.</p>\r\n</li><li data-start=\"514\" data-end=\"585\">\r\n<p data-start=\"516\" data-end=\"585\"><strong data-start=\"516\" data-end=\"527\">Contact</strong>: The contact person or team for the device (if provided).</p>\r\n</li><li data-start=\"586\" data-end=\"645\">\r\n<p data-start=\"588\" data-end=\"645\"><strong data-start=\"588\" data-end=\"603\">Description</strong>: Any description provided for the device.</p>\r\n</li><li data-start=\"646\" data-end=\"713\">\r\n<p data-start=\"648\" data-end=\"713\"><strong data-start=\"648\" data-end=\"654\">OS</strong>: The operating system running on the device (if detected).</p>\r\n</li><li data-start=\"714\" data-end=\"783\">\r\n<p data-start=\"716\" data-end=\"783\"><strong data-start=\"716\" data-end=\"727\">Up Time</strong>: The amount of time the device has been up and running.</p>\r\n</li><li data-start=\"784\" data-end=\"860\">\r\n<p data-start=\"786\" data-end=\"860\"><strong data-start=\"786\" data-end=\"794\">SNMP</strong>: Indicates if SNMP is enabled on the device (<strong data-start=\"840\" data-end=\"846\">Up</strong> or <strong data-start=\"850\" data-end=\"858\">Down</strong>).</p>\r\n</li><li data-start=\"861\" data-end=\"929\">\r\n<p data-start=\"863\" data-end=\"929\"><strong data-start=\"863\" data-end=\"873\">Status</strong>: The current status of the device (<strong data-start=\"909\" data-end=\"915\">Up</strong> or <strong data-start=\"919\" data-end=\"927\">Down</strong>).</p>\r\n</li><li data-start=\"930\" data-end=\"994\">\r\n<p data-start=\"932\" data-end=\"994\"><strong data-start=\"932\" data-end=\"946\">Last Check</strong>: The last time the device’s status was checked.</p></li></ul><h3 data-start=\"1001\" data-end=\"1025\"><strong data-start=\"1005\" data-end=\"1025\">Actions Panel</strong></h3>\r\n<ul data-start=\"1026\" data-end=\"1340\"><li data-start=\"1026\" data-end=\"1134\">\r\n<p data-start=\"1028\" data-end=\"1134\"><strong data-start=\"1028\" data-end=\"1048\">Choose an action</strong>: Dropdown to select actions such as editing, deleting, or exporting selected devices.</p>\r\n</li><li data-start=\"1135\" data-end=\"1174\">\r\n<p data-start=\"1137\" data-end=\"1174\"><strong data-start=\"1137\" data-end=\"1143\">Go</strong>: Executes the selected action.</p>\r\n</li><li data-start=\"1175\" data-end=\"1254\">\r\n<p data-start=\"1177\" data-end=\"1254\"><strong data-start=\"1177\" data-end=\"1187\">Filter</strong>: Filter the list of discovered devices based on specific criteria.</p>\r\n</li><li data-start=\"1255\" data-end=\"1340\">\r\n<p data-start=\"1257\" data-end=\"1340\"><strong data-start=\"1257\" data-end=\"1267\">Export</strong>: Export the discovered devices list to a file for reporting or analysis.</p></li></ul><h3 data-start=\"1786\" data-end=\"1815\"><strong data-start=\"1790\" data-end=\"1814\">Troubleshooting Tips</strong>:</h3>\r\n<ul data-start=\"1816\" data-end=\"2210\"><li data-start=\"1816\" data-end=\"1928\">\r\n<p data-start=\"1818\" data-end=\"1928\"><strong data-start=\"1818\" data-end=\"1833\">Down Status</strong>: If the <strong data-start=\"1842\" data-end=\"1852\">Status</strong> is <strong data-start=\"1856\" data-end=\"1864\">Down</strong>, check the network connectivity or configuration of the device.</p>\r\n</li><li data-start=\"1929\" data-end=\"2075\">\r\n<p data-start=\"1931\" data-end=\"2075\"><strong data-start=\"1931\" data-end=\"1947\">Not Detected</strong>: Devices marked as <strong data-start=\"1967\" data-end=\"1983\">Not Detected</strong> may require manual configuration or troubleshooting to ensure they are properly discovered.</p>\r\n</li><li data-start=\"2076\" data-end=\"2210\">\r\n<p data-start=\"2078\" data-end=\"2210\"><strong data-start=\"2078\" data-end=\"2093\">SNMP Issues</strong>: If SNMP is not enabled, make sure SNMP settings are configured correctly on the device to allow network monitoring.</p></li></ul><p><br></p>',0,NULL,'active','2025-08-29 12:14:03','2025-08-29 12:14:03'),(32,'SNMP Settings','snmp-settings','<h2 data-start=\"314\" data-end=\"349\">Purpose of SNMP Credentials</h2><p data-start=\"350\" data-end=\"505\">SNMP credentials allow the Network Management System (NMS) to <strong data-start=\"412\" data-end=\"471\">securely collect performance, fault, and inventory data</strong> from network devices and servers.</p><p data-start=\"507\" data-end=\"580\">The credentials determine <strong data-start=\"533\" data-end=\"579\">what data can be accessed and how securely</strong>.</p><hr data-start=\"582\" data-end=\"585\"><h1 data-start=\"587\" data-end=\"608\">SNMP Version</h1><h3 data-start=\"610\" data-end=\"637\"><strong data-start=\"614\" data-end=\"637\">Field: SNMP Version</strong></h3><p data-start=\"638\" data-end=\"650\"><strong data-start=\"638\" data-end=\"650\">Options:</strong></p><ul data-start=\"651\" data-end=\"701\">\r\n<li data-start=\"651\" data-end=\"662\">\r\n<p data-start=\"653\" data-end=\"662\">SNMP v1</p>\r\n</li>\r\n<li data-start=\"663\" data-end=\"675\">\r\n<p data-start=\"665\" data-end=\"675\">SNMP v2c</p>\r\n</li>\r\n<li data-start=\"676\" data-end=\"701\">\r\n<p data-start=\"678\" data-end=\"701\">SNMP v3 (Recommended)</p>\r\n</li>\r\n</ul><h3 data-start=\"703\" data-end=\"719\">Explanation:</h3><ul data-start=\"720\" data-end=\"896\">\r\n<li data-start=\"720\" data-end=\"796\">\r\n<p data-start=\"722\" data-end=\"796\"><strong data-start=\"722\" data-end=\"739\">SNMP v1 / v2c</strong> use a community string for authentication (less secure).</p>\r\n</li>\r\n<li data-start=\"797\" data-end=\"896\">\r\n<p data-start=\"799\" data-end=\"896\"><strong data-start=\"799\" data-end=\"810\">SNMP v3</strong> provides encryption and authentication and should be used in production environments.</p>\r\n</li>\r\n</ul><hr data-start=\"898\" data-end=\"901\"><h1 data-start=\"903\" data-end=\"949\">SNMP Community String (v1 / v2c Only)</h1><h3 data-start=\"951\" data-end=\"980\"><strong data-start=\"955\" data-end=\"980\">Field: Read Community</strong></h3><p data-start=\"981\" data-end=\"991\">Example:</p><pre class=\"overflow-visible! px-0!\" data-start=\"992\" data-end=\"1013\"><div class=\"contain-inline-size rounded-2xl corner-superellipse/1.1 relative bg-token-sidebar-surface-primary\"><div class=\"sticky top-[calc(--spacing(9)+var(--header-height))] @w-xl/main:top-9\"><div class=\"absolute end-0 bottom-0 flex h-9 items-center pe-2\"><div class=\"bg-token-bg-elevated-secondary text-token-text-secondary flex items-center gap-4 rounded-sm px-2 font-sans text-xs\"></div></div></div><div class=\"overflow-y-auto p-4\" dir=\"ltr\"><code class=\"whitespace-pre!\"><span class=\"hljs-keyword\">public</span>\r\nnms_ro\r\n</code></div></div></pre><h3 data-start=\"1015\" data-end=\"1031\">Explanation:</h3><ul data-start=\"1032\" data-end=\"1157\">\r\n<li data-start=\"1032\" data-end=\"1103\">\r\n<p data-start=\"1034\" data-end=\"1103\">A <strong data-start=\"1036\" data-end=\"1058\">read-only password</strong> used by the NMS to retrieve monitoring data.</p>\r\n</li>\r\n<li data-start=\"1104\" data-end=\"1157\">\r\n<p data-start=\"1106\" data-end=\"1157\">Should be <strong data-start=\"1116\" data-end=\"1156\">non-default and restricted by IP ACL</strong>.<br></p></li></ul><ul data-start=\"1256\" data-end=\"1406\">\r\n</ul><hr data-start=\"1408\" data-end=\"1411\"><h1 data-start=\"1413\" data-end=\"1463\">SNMP v3 Security Parameters (Recommended)</h1><p data-start=\"1465\" data-end=\"1514\">SNMP v3 uses <strong data-start=\"1478\" data-end=\"1513\">user-based security model (USM)</strong>.</p><hr data-start=\"1516\" data-end=\"1519\"><h2 data-start=\"1521\" data-end=\"1543\">SNMP v3 Username</h2><h3 data-start=\"1545\" data-end=\"1568\"><strong data-start=\"1549\" data-end=\"1568\">Field: Username</strong></h3><p data-start=\"1569\" data-end=\"1577\">Example:</p><pre class=\"overflow-visible! px-0!\" data-start=\"1578\" data-end=\"1606\"><div class=\"contain-inline-size rounded-2xl corner-superellipse/1.1 relative bg-token-sidebar-surface-primary\"><div class=\"sticky top-[calc(--spacing(9)+var(--header-height))] @w-xl/main:top-9\"><div class=\"absolute end-0 bottom-0 flex h-9 items-center pe-2\"><div class=\"bg-token-bg-elevated-secondary text-token-text-secondary flex items-center gap-4 rounded-sm px-2 font-sans text-xs\"></div></div></div><div class=\"overflow-y-auto p-4\" dir=\"ltr\"><code class=\"whitespace-pre!\"><span class=\"hljs-attribute\">nmsuser</span>\r\nmonitor_user\r\n</code></div></div></pre><h3 data-start=\"1608\" data-end=\"1624\">Explanation:</h3><ul data-start=\"1625\" data-end=\"1701\">\r\n<li data-start=\"1625\" data-end=\"1666\">\r\n<p data-start=\"1627\" data-end=\"1666\">Unique SNMP user account on the device.</p>\r\n</li>\r\n<li data-start=\"1667\" data-end=\"1701\">\r\n<p data-start=\"1669\" data-end=\"1701\">Used by the NMS to authenticate.</p>\r\n</li>\r\n</ul><hr data-start=\"1703\" data-end=\"1706\"><h2 data-start=\"1708\" data-end=\"1737\">Authentication Protocol</h2><h3 data-start=\"1739\" data-end=\"1767\"><strong data-start=\"1743\" data-end=\"1767\">Field: Auth Protocol</strong></h3><p data-start=\"1768\" data-end=\"1780\"><strong data-start=\"1768\" data-end=\"1780\">Options:</strong></p><ul data-start=\"1781\" data-end=\"1830\">\r\n<li data-start=\"1781\" data-end=\"1788\">\r\n<p data-start=\"1783\" data-end=\"1788\">MD5</p>\r\n</li>\r\n<li data-start=\"1789\" data-end=\"1796\">\r\n<p data-start=\"1791\" data-end=\"1796\">SHA</p>\r\n</li>\r\n<li data-start=\"1797\" data-end=\"1830\">\r\n<p data-start=\"1799\" data-end=\"1830\">SHA-256 / SHA-512 (Recommended)</p>\r\n</li>\r\n</ul><h3 data-start=\"1832\" data-end=\"1848\">Explanation:</h3><ul data-start=\"1849\" data-end=\"1945\">\r\n<li data-start=\"1849\" data-end=\"1897\">\r\n<p data-start=\"1851\" data-end=\"1897\">Used to verify the identity of the NMS system.</p>\r\n</li>\r\n<li data-start=\"1898\" data-end=\"1945\">\r\n<p data-start=\"1900\" data-end=\"1945\">SHA-based protocols are more secure than MD5.</p>\r\n</li>\r\n</ul><hr data-start=\"1947\" data-end=\"1950\"><h2 data-start=\"1952\" data-end=\"1981\">Authentication Password</h2><h3 data-start=\"1983\" data-end=\"2011\"><strong data-start=\"1987\" data-end=\"2011\">Field: Auth Password</strong></h3><p data-start=\"2012\" data-end=\"2020\">Example:</p><pre class=\"overflow-visible! px-0!\" data-start=\"2021\" data-end=\"2048\"><div class=\"contain-inline-size rounded-2xl corner-superellipse/1.1 relative bg-token-sidebar-surface-primary\"><div class=\"sticky top-[calc(--spacing(9)+var(--header-height))] @w-xl/main:top-9\"><div class=\"absolute end-0 bottom-0 flex h-9 items-center pe-2\"><div class=\"bg-token-bg-elevated-secondary text-token-text-secondary flex items-center gap-4 rounded-sm px-2 font-sans text-xs\"></div></div></div><div class=\"overflow-y-auto p-4\" dir=\"ltr\"><code class=\"whitespace-pre!\"><span class=\"hljs-attribute\">MySecureAuthPass123</span>\r\n</code></div></div></pre><h3 data-start=\"2050\" data-end=\"2066\">Explanation:</h3><ul data-start=\"2067\" data-end=\"2160\">\r\n<li data-start=\"2067\" data-end=\"2107\">\r\n<p data-start=\"2069\" data-end=\"2107\">Password used for SNMP authentication.</p>\r\n</li>\r\n<li data-start=\"2108\" data-end=\"2160\">\r\n<p data-start=\"2110\" data-end=\"2160\">Must meet security policy complexity requirements.</p>\r\n</li>\r\n</ul><hr data-start=\"2162\" data-end=\"2165\"><h2 data-start=\"2167\" data-end=\"2202\">Privacy (Encryption) Protocol</h2><h3 data-start=\"2204\" data-end=\"2232\"><strong data-start=\"2208\" data-end=\"2232\">Field: Priv Protocol</strong></h3><p data-start=\"2233\" data-end=\"2245\"><strong data-start=\"2233\" data-end=\"2245\">Options:</strong></p><ul data-start=\"2246\" data-end=\"2273\">\r\n<li data-start=\"2246\" data-end=\"2253\">\r\n<p data-start=\"2248\" data-end=\"2253\">DES</p>\r\n</li>\r\n<li data-start=\"2254\" data-end=\"2273\">\r\n<p data-start=\"2256\" data-end=\"2273\">AES (Recommended)</p>\r\n</li>\r\n</ul><h3 data-start=\"2275\" data-end=\"2291\">Explanation:</h3><ul data-start=\"2292\" data-end=\"2383\">\r\n<li data-start=\"2292\" data-end=\"2324\">\r\n<p data-start=\"2294\" data-end=\"2324\">Encrypts SNMP data in transit.</p>\r\n</li>\r\n<li data-start=\"2325\" data-end=\"2383\">\r\n<p data-start=\"2327\" data-end=\"2383\">AES is strongly recommended for compliance and security.</p>\r\n</li>\r\n</ul><hr data-start=\"2385\" data-end=\"2388\"><h2 data-start=\"2390\" data-end=\"2412\">Privacy Password</h2><h3 data-start=\"2414\" data-end=\"2442\"><strong data-start=\"2418\" data-end=\"2442\">Field: Priv Password</strong></h3><p data-start=\"2443\" data-end=\"2451\">Example:</p><pre class=\"overflow-visible! px-0!\" data-start=\"2452\" data-end=\"2479\"><div class=\"contain-inline-size rounded-2xl corner-superellipse/1.1 relative bg-token-sidebar-surface-primary\"><div class=\"sticky top-[calc(--spacing(9)+var(--header-height))] @w-xl/main:top-9\"><div class=\"absolute end-0 bottom-0 flex h-9 items-center pe-2\"><div class=\"bg-token-bg-elevated-secondary text-token-text-secondary flex items-center gap-4 rounded-sm px-2 font-sans text-xs\"></div></div></div><div class=\"overflow-y-auto p-4\" dir=\"ltr\"><code class=\"whitespace-pre!\"><span class=\"hljs-attribute\">MySecurePrivPass456</span>\r\n</code></div></div></pre><h3 data-start=\"2481\" data-end=\"2497\">Explanation:</h3><ul data-start=\"2498\" data-end=\"2567\">\r\n<li data-start=\"2498\" data-end=\"2567\">\r\n<p data-start=\"2500\" data-end=\"2567\">Encryption password used to protect SNMP traffic from interception.</p>\r\n</li>\r\n</ul><hr data-start=\"2569\" data-end=\"2572\"><h1 data-start=\"2574\" data-end=\"2602\">SNMP Security Level</h1><h3 data-start=\"2604\" data-end=\"2633\"><strong data-start=\"2608\" data-end=\"2633\">Field: Security Level</strong></h3><p data-start=\"2634\" data-end=\"2646\"><strong data-start=\"2634\" data-end=\"2646\">Options:</strong></p><ul data-start=\"2647\" data-end=\"2705\">\r\n<li data-start=\"2647\" data-end=\"2663\">\r\n<p data-start=\"2649\" data-end=\"2663\">noAuthNoPriv</p>\r\n</li>\r\n<li data-start=\"2664\" data-end=\"2678\">\r\n<p data-start=\"2666\" data-end=\"2678\">authNoPriv</p>\r\n</li>\r\n<li data-start=\"2679\" data-end=\"2705\">\r\n<p data-start=\"2681\" data-end=\"2705\">authPriv (Recommended)</p>\r\n</li>\r\n</ul><h3 data-start=\"2707\" data-end=\"2723\">Explanation:</h3><div class=\"TyagGW_tableContainer\"><div tabindex=\"-1\" class=\"group TyagGW_tableWrapper flex flex-col-reverse w-fit\"><table data-start=\"2724\" data-end=\"2919\" class=\"w-fit min-w-(--thread-content-width)\"><thead data-start=\"2724\" data-end=\"2747\"><tr data-start=\"2724\" data-end=\"2747\"><th data-start=\"2724\" data-end=\"2732\" data-col-size=\"sm\">Level</th><th data-start=\"2732\" data-end=\"2747\" data-col-size=\"md\">Description</th></tr></thead><tbody data-start=\"2773\" data-end=\"2919\"><tr data-start=\"2773\" data-end=\"2823\"><td data-start=\"2773\" data-end=\"2788\" data-col-size=\"sm\">noAuthNoPriv</td><td data-start=\"2788\" data-end=\"2823\" data-col-size=\"md\">No authentication or encryption</td></tr><tr data-start=\"2824\" data-end=\"2860\"><td data-start=\"2824\" data-end=\"2837\" data-col-size=\"sm\">authNoPriv</td><td data-start=\"2837\" data-end=\"2860\" data-col-size=\"md\">Authentication only</td></tr><tr data-start=\"2861\" data-end=\"2919\"><td data-start=\"2861\" data-end=\"2872\" data-col-size=\"sm\">authPriv</td><td data-start=\"2872\" data-end=\"2919\" data-col-size=\"md\">Authentication + Encryption (Best Practice)</td></tr></tbody></table></div></div><ul data-start=\"3080\" data-end=\"3168\"></ul><h2 data-start=\"3175\" data-end=\"3202\">SNMP View / Access Level</h2><h3 data-start=\"3204\" data-end=\"3228\"><strong data-start=\"3208\" data-end=\"3228\">Field: SNMP View</strong></h3><p data-start=\"3229\" data-end=\"3237\">Example:</p><pre class=\"overflow-visible! px-0!\" data-start=\"3238\" data-end=\"3268\"><div class=\"contain-inline-size rounded-2xl corner-superellipse/1.1 relative bg-token-sidebar-surface-primary\"><div class=\"sticky top-[calc(--spacing(9)+var(--header-height))] @w-xl/main:top-9\"><div class=\"absolute end-0 bottom-0 flex h-9 items-center pe-2\"><div class=\"bg-token-bg-elevated-secondary text-token-text-secondary flex items-center gap-4 rounded-sm px-2 font-sans text-xs\"></div></div></div><div class=\"overflow-y-auto p-4\" dir=\"ltr\"><code class=\"whitespace-pre!\">systemonly\r\n<span class=\"hljs-attribute\">all</span>\r\nnmsview\r\n</code></div></div></pre><h3 data-start=\"3270\" data-end=\"3286\">Explanation:</h3><ul data-start=\"3287\" data-end=\"3393\">\r\n<li data-start=\"3287\" data-end=\"3333\">\r\n<p data-start=\"3289\" data-end=\"3333\">Controls which MIB objects the NMS can read.</p>\r\n</li>\r\n<li data-start=\"3334\" data-end=\"3393\">\r\n<p data-start=\"3336\" data-end=\"3393\"><strong data-start=\"3336\" data-end=\"3392\">Full monitoring requires view including <code data-start=\"3378\" data-end=\"3382\">.1</code> subtree</strong>.</p>\r\n</li>\r\n</ul><hr data-start=\"3395\" data-end=\"3398\"><h1 data-start=\"3400\" data-end=\"3418\">SNMP Port</h1><h3 data-start=\"3420\" data-end=\"3444\"><strong data-start=\"3424\" data-end=\"3444\">Field: SNMP Port</strong></h3><p data-start=\"3445\" data-end=\"3453\">Default:</p><pre class=\"overflow-visible! px-0!\" data-start=\"3454\" data-end=\"3471\"><div class=\"contain-inline-size rounded-2xl corner-superellipse/1.1 relative bg-token-sidebar-surface-primary\"><div class=\"sticky top-[calc(--spacing(9)+var(--header-height))] @w-xl/main:top-9\"><div class=\"absolute end-0 bottom-0 flex h-9 items-center pe-2\"><div class=\"bg-token-bg-elevated-secondary text-token-text-secondary flex items-center gap-4 rounded-sm px-2 font-sans text-xs\"></div></div></div><div class=\"overflow-y-auto p-4\" dir=\"ltr\"><code class=\"whitespace-pre!\"><span class=\"hljs-number\">161</span> (UDP)\r\n</code></div></div></pre><h3 data-start=\"3473\" data-end=\"3489\">Explanation:</h3><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><ul data-start=\"3490\" data-end=\"3573\">\r\n<li data-start=\"3490\" data-end=\"3523\">\r\n<p data-start=\"3492\" data-end=\"3523\">Standard port for SNMP queries.</p>\r\n</li>\r\n<li data-start=\"3524\" data-end=\"3573\">\r\n<p data-start=\"3526\" data-end=\"3573\">Custom ports may be used for security policies.</p></li></ul>',0,NULL,'active','2026-01-30 13:20:00','2026-01-30 13:20:00');
